import type { Drill } from "./types";

// Finance / senior drills, keyed by module slug — 25 per module.
// Pitched at a VP of Finance / CFO-track executive: board decks, investor
// communication, capital allocation, guidance, financing negotiations. Merged into course.ts.
export const FINANCE_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-fin-senior-01","level":"senior","profession":"finance","title":"The board summary that opens with methodology","scenario":"Your Q3 board deck executive summary opens with two paragraphs on how the forecast model was rebuilt. The actual headline — revenue beat plan by 4% and cash conversion improved — appears on the second page. The chair reads the first page only.","task":"Write a 2-3 sentence executive summary that leads with the quarter's headline.","tips":["Sentence one: the result and whether it beats or misses plan.","Model methodology is an appendix topic, not an opener.","Directors skim — make the first line carry the quarter."],"focus":["structure","clarity"],"placeholder":"Q3 revenue beat plan by 4% and cash conversion improved to 92% —"},
    {"id":"lead-fin-senior-02","level":"senior","profession":"finance","title":"The covenant warning buried in trailing detail","scenario":"Your leverage ratio will breach the covenant threshold next quarter if EBITDA lands at the low end of forecast. Your draft email to the CEO recaps three months of trading history before mentioning the breach risk in paragraph four.","task":"Rewrite the email opening so the covenant risk is the first sentence.","tips":["Lead with the risk and the timeline: possible breach next quarter.","Trading history is evidence — it follows the headline.","Name the decision or action you need from the CEO."],"focus":["clarity","impact"],"placeholder":"We are at risk of breaching our leverage covenant next quarter if —"},
    {"id":"lead-fin-senior-03","level":"senior","profession":"finance","title":"The remediation update that starts with history","scenario":"The material weakness in revenue controls flagged last year is now fully remediated and retested. Your audit-committee memo opens with a chronology of the original finding before stating the outcome the committee actually wants: it's fixed.","task":"Write a 2-sentence opening that states the remediation outcome first.","tips":["First sentence: remediated, retested, closed.","The history of the finding is context, placed after.","The committee reads for the verdict, not the journey."],"focus":["structure","concision"]},
    {"id":"lead-fin-senior-04","level":"senior","profession":"finance","title":"The covenant amendment ask","scenario":"You need your lead bank to agree to a one-quarter covenant amendment while an acquisition integrates. Your draft email spends three paragraphs on the strategic rationale for the deal before making the request.","task":"Write an email opening that puts the specific ask — the amendment and the deadline — in sentence one.","tips":["Lead with what you want, from whom, by when.","A banker who knows the ask reads the rationale differently.","Keep the deal rationale to two supporting sentences."],"focus":["clarity","impact"],"placeholder":"We are requesting a one-quarter amendment to the leverage covenant, agreed by March 15 —"},
    {"id":"lead-fin-senior-05","level":"senior","profession":"finance","title":"Lowering the year, sentence one","scenario":"The reforecast is done and the conclusion is unavoidable: full-year guidance needs to come down. Your note to the CEO opens with a careful tour of the assumptions before landing on the recommendation in the final line.","task":"Write a 2-3 sentence note that recommends the guidance cut in the first sentence.","tips":["Say it plainly: I recommend we lower full-year guidance.","Give the new range immediately, not at the end.","Assumptions are support — one line, with the detail attached."],"focus":["clarity","impact"],"placeholder":"I recommend we lower full-year guidance to $410-425M."},
    {"id":"lead-fin-senior-06","level":"senior","profession":"finance","title":"The runway note to the chair","scenario":"Cash runway has shortened from 18 months to 13 because collections slowed and one large renewal slipped. The board chair asked for a quick written update. Your draft opens with the working-capital mechanics.","task":"Write a 2-3 sentence update that leads with the runway number and the change.","tips":["First sentence: runway is now 13 months, down from 18.","Then the two drivers, one line each.","End with what you are doing about it."],"focus":["structure","precision"],"placeholder":"Runway is now 13 months, down from 18 at last board meeting."},
    {"id":"lead-fin-senior-07","level":"senior","profession":"finance","title":"The capital-allocation memo with a buried verdict","scenario":"Your capital-allocation memo weighs debt paydown, a buyback, and two internal investments across six pages of analysis. Your recommendation — pay down the revolver first — appears in the final paragraph, where half the board will never reach it.","task":"Write the memo's opening 2 sentences: the recommendation, then the one-line reason.","tips":["Recommendation in sentence one, in plain words.","The six pages become supporting analysis, not a preamble.","A clear verdict up front makes the analysis easier to follow, not redundant."],"focus":["structure","clarity"],"placeholder":"I recommend we direct this year's excess cash to paying down the revolver."},
    {"id":"lead-fin-senior-08","level":"senior","profession":"finance","title":"The earnings call's first sentence","scenario":"You open the prepared remarks on the earnings call. The quarter's story is simple: revenue grew 11%, margins expanded, and guidance holds. Your current draft begins with safe-harbor housekeeping and a tour of the agenda.","task":"Write the first two sentences of prepared remarks that lead with the quarter's headline.","tips":["Investors form their view in the first minute — spend it on results.","Numbers first: growth, margin, guidance status.","Agenda and housekeeping can be one clause, not an opening act."],"focus":["impact","concision"]},
    {"id":"lead-fin-senior-09","level":"senior","profession":"finance","title":"The concentration risk you're easing into","scenario":"Your largest customer — 18% of revenue — has delayed their renewal decision by a quarter. The CEO needs to know today. Your draft message walks through the account history before naming the risk.","task":"Write a 2-3 sentence message that leads with the risk and its size.","tips":["First line: who, how much revenue, what changed.","History of the account is background, kept brief.","Say what you need: a decision, a call, or just awareness."],"focus":["clarity","impact"],"placeholder":"Our largest customer (18% of revenue) has pushed their renewal decision to Q2."},
    {"id":"lead-fin-senior-10","level":"senior","profession":"finance","title":"The pre-close miss heads-up","scenario":"Three days before the quarter closes, it's clear revenue will land 3% below the number you gave the board. You're drafting the heads-up to the CEO and instinctively opening with everything the team did to close the gap.","task":"Write a heads-up that states the expected miss in the first sentence.","tips":["Lead with the number: about 3% below plan.","Effort narrative comes after — briefly, if at all.","Early and plain beats polished and late."],"focus":["clarity","precision"],"placeholder":"We will close Q2 roughly 3% below the plan I gave the board."},
    {"id":"lead-fin-senior-11","level":"senior","profession":"finance","title":"The investor follow-up that answers last","scenario":"An institutional investor emailed one question after the call: is the gross-margin improvement structural or one-time? It's structural, driven by the pricing change. Your reply drafts three paragraphs of margin context before answering.","task":"Rewrite the reply so the direct answer is the first sentence.","tips":["Answer the binary first: structural.","One sentence of mechanism is usually enough support.","Investors reread first lines, not third paragraphs."],"focus":["concision","clarity"],"placeholder":"Structural — the improvement comes from the pricing change, not one-time items."},
    {"id":"lead-fin-senior-12","level":"senior","profession":"finance","title":"The board approval needed by Friday","scenario":"The new credit facility terms expire Friday and you need board sign-off before then. Your email to directors opens with the negotiation backstory rather than the approval request and its deadline.","task":"Write an email opening that leads with the approval needed and the deadline.","tips":["Sentence one: what approval, by when, and why the date is real.","Backstory belongs in an attached summary.","Make the requested action unmissable for a director skimming on a phone."],"focus":["clarity","structure"],"placeholder":"I need board approval of the new credit facility by Friday, when the agreed terms expire."},
    {"id":"lead-fin-senior-13","level":"senior","profession":"finance","title":"The monthly review that warms up slowly","scenario":"You open the monthly business review with department heads. The one thing they must act on: discretionary spend is running 12% over plan and freezes start next week. Your usual opening tours each P&L line first.","task":"Write a 2-sentence spoken opening that leads with the action and the reason.","tips":["Open with what changes for them: freezes start next week.","Give the one number that justifies it.","Line-by-line detail comes later for those who need it."],"focus":["impact","concision"]},
    {"id":"lead-fin-senior-14","level":"senior","profession":"finance","title":"The insurance renewal recommendation","scenario":"The company's liability premium is doubling at renewal. You've evaluated alternatives and recommend accepting the increase but raising the deductible to offset half of it. Your memo to the CEO opens with the state of the insurance market.","task":"Write a 2-sentence memo opening: recommendation first, market context second.","tips":["Lead with the recommendation and its net cost effect.","Market conditions explain the recommendation; they don't precede it.","Keep the ask actionable: approve by the renewal date."],"focus":["structure","clarity"]},
    {"id":"lead-fin-senior-15","level":"senior","profession":"finance","title":"The diligence finding that changes the deal","scenario":"Quality-of-earnings work on the acquisition target found that a third of their reported EBITDA depends on a pricing arrangement that expires next year. Your update to the deal team narrates the diligence process before the finding.","task":"Write a 2-3 sentence update that leads with the finding and what it means for price.","tips":["First sentence: the finding and its size.","Second: the implication — the multiple is built on softer earnings.","Process narration adds nothing a deal team needs first."],"focus":["clarity","impact"],"placeholder":"A third of the target's EBITDA depends on a pricing arrangement that expires next year."},
    {"id":"lead-fin-senior-16","level":"senior","profession":"finance","title":"The one message for the rating agency","scenario":"You're prepping the CEO for a rating-agency review call. If the analysts remember one thing, it should be that leverage falls below 2.5x by year end under the base plan. Your prep note lists twelve talking points with no hierarchy.","task":"Write the prep note's opening line: the single message the call must land.","tips":["Name the one takeaway explicitly — 'if they remember one thing…'.","Twelve equal points means no point lands.","Order the rest as support for that message."],"focus":["clarity","impact"],"placeholder":"The one message: leverage falls below 2.5x by year end under our base plan."},
    {"id":"lead-fin-senior-17","level":"senior","profession":"finance","title":"The cost-program milestone, said plainly","scenario":"The cost program hit its first milestone: $8M of the $20M target is actioned, a quarter ahead of schedule. Your all-hands update opens by re-explaining why the program exists — the company has heard that three times.","task":"Write a 2-sentence all-hands opening that leads with the milestone.","tips":["People want the score: $8M of $20M, ahead of schedule.","The rationale recap can be one clause, not a section.","Progress stated plainly builds more confidence than context."],"focus":["impact","concision"],"placeholder":"We've actioned $8M of the $20M cost target — a quarter ahead of schedule."},
    {"id":"lead-fin-senior-18","level":"senior","profession":"finance","title":"The director's margin question","scenario":"A director emailed: why did gross margin decline two points this quarter? The answer is a deliberate trade — you priced two strategic deals aggressively to win multi-year commitments. Your reply drafts the full pricing philosophy first.","task":"Write a reply that answers the question in sentence one, then gives the context.","tips":["Answer first: it was a deliberate pricing trade on two strategic deals.","Then quantify: which deals, what margin, what they secure.","Philosophy essays make directors suspect evasion."],"focus":["clarity","structure"],"placeholder":"The two-point decline was deliberate — we priced two strategic deals to win multi-year commitments."},
    {"id":"lead-fin-senior-19","level":"senior","profession":"finance","title":"The hedging loss, number first","scenario":"The currency hedge you put on last quarter is $1.4M underwater after an unexpected rate move. It's within policy limits, but the CEO should hear it from you first. Your draft opens with a refresher on the hedging policy.","task":"Write a 2-3 sentence message that leads with the loss and its status.","tips":["First line: the number and that it's within policy limits.","Policy refresher is one supporting clause.","Bad news travels — make sure your version arrives first and leads with the fact."],"focus":["clarity","precision"],"placeholder":"Our currency hedge is $1.4M underwater after this week's rate move — within policy limits."},
    {"id":"lead-fin-senior-20","level":"senior","profession":"finance","title":"The budget kickoff ask","scenario":"Budget season opens Monday. Every department must submit plans by October 14 with a 5% reduction to baseline. Your kickoff email to leaders drafts two paragraphs on the macro environment before stating either requirement.","task":"Write an email opening that puts the deadline and the 5% requirement in the first sentence.","tips":["Leaders forward the first line to their teams — make it complete.","Macro context is one supporting sentence, not the lead.","Two requirements, one sentence: date and number."],"focus":["clarity","structure"]},
    {"id":"lead-fin-senior-21","level":"senior","profession":"finance","title":"The audit fee overrun","scenario":"The external audit will run $150K over the approved fee because of the acquisition's first-year consolidation work. You need audit-committee approval. Your memo opens with a description of the audit scope.","task":"Write a 2-sentence memo opening: the approval ask and the reason.","tips":["Lead with the ask: approve $150K of additional audit fees.","One-line reason: first-year acquisition consolidation.","Scope detail is for the appendix or the meeting itself."],"focus":["clarity","concision"]},
    {"id":"lead-fin-senior-22","level":"senior","profession":"finance","title":"The headcount ask you keep softening","scenario":"You need CEO approval for two FP&A hires to support the acquisition integration — the team is at capacity and the board is asking for more scenario work. Your draft opens with an apology for adding cost during a cost program.","task":"Write a message that leads with the ask and the business reason, no apology.","tips":["Sentence one: the ask — two FP&A hires — and what breaks without them.","An apologetic opening argues against your own request.","Acknowledge the cost-program tension after the case, briefly."],"focus":["clarity","impact"],"placeholder":"I need approval for two FP&A hires to support the integration —"},
    {"id":"lead-fin-senior-23","level":"senior","profession":"finance","title":"The ERP delay, new date first","scenario":"The ERP go-live is slipping from June to September — data migration testing surfaced errors that must be fixed before cutover. Your steering-committee note opens with a detailed account of the testing cycle.","task":"Write a 2-3 sentence note that states the new date in the first sentence.","tips":["Lead with the decision: go-live moves to September.","One sentence on why; one on what it costs or protects.","Committees need the new plan before the diagnosis."],"focus":["clarity","structure"],"placeholder":"ERP go-live moves from June to September."},
    {"id":"lead-fin-senior-24","level":"senior","profession":"finance","title":"Sixty seconds with your largest investor","scenario":"News of your guidance revision goes out at market open tomorrow. You've committed to calling your largest investor tonight and may only get voicemail. You have to lead with the point — there is no room for wind-up.","task":"Write a 3-4 sentence voicemail script that states the news in the first sentence.","tips":["First sentence: what's being announced and when.","Second: the one-line reason.","Close with when they can reach you — then stop."],"focus":["concision","impact"]},
    {"id":"lead-fin-senior-25","level":"senior","profession":"finance","title":"The good news you're underselling","scenario":"The refinancing closed at a rate 120 basis points below the old facility, saving roughly $2M a year in interest. Your update to the board buries this in a treasury-activity roundup between routine items.","task":"Write a 2-sentence update that leads with the win and its annual value.","tips":["Good news deserves the same BLUF discipline as bad news.","Quantify the headline: $2M a year, 120bps better.","Routine treasury items follow, clearly separated."],"focus":["impact","clarity"],"placeholder":"We closed the refinancing 120bps below the old facility — roughly $2M a year in interest savings."}
  ],
  "start-with-the-audience": [
    {"id":"audience-fin-senior-01","level":"senior","profession":"finance","title":"EBITDA vs cash for the newest director","scenario":"Your newest board member — a founder with a product background — asked after the meeting why the company reports positive EBITDA but burned cash this quarter. Your first instinct is a working-capital walk with five reconciling items.","task":"Write a 3-4 sentence explanation a non-finance director will genuinely understand.","tips":["Start from their confusion: profit on paper, cash out the door.","Pick the one or two drivers that matter; skip the full reconciliation.","Use plain mechanics: customers paying later, inventory bought earlier."],"focus":["audience","clarity"],"placeholder":"We earned the profit, but the cash hasn't arrived yet —"},
    {"id":"audience-fin-senior-02","level":"senior","profession":"finance","title":"Record revenue, frozen hiring","scenario":"At the all-hands, employees will hear 'record revenue' and 'hiring freeze' in the same presentation. Your draft explains the freeze with margin percentages and cash-conversion ratios — language that answers a question nobody in the room is asking.","task":"Write a 3-4 sentence explanation of the freeze pitched at what employees actually want to know.","tips":["Their real question: is the company OK, and is my job safe?","Answer that before any ratio.","Translate the numbers into one plain trade-off the company is making."],"focus":["audience","clarity"]},
    {"id":"audience-fin-senior-03","level":"senior","profession":"finance","title":"Payment terms, translated for sales","scenario":"You need sales leadership to stop giving 90-day payment terms to close deals. Your draft memo explains DSO trends and working-capital drag — concepts that won't survive contact with a sales team meeting.","task":"Write a 3-4 sentence note that puts the terms issue in sales language: deals, quota, and what changes for them.","tips":["Lead with what changes for them: terms above 60 days now need your sign-off.","Translate the drag into something concrete — cash that funds their headcount.","One rule, one reason, one exception path."],"focus":["audience","impact"],"placeholder":"Starting this quarter, any deal with payment terms beyond 60 days needs my sign-off before quote."},
    {"id":"audience-fin-senior-04","level":"senior","profession":"finance","title":"Deferred revenue without the accounting","scenario":"Your investor letter must explain why revenue growth looks slower this year even though bookings accelerated — a shift toward multi-year deals recognized over time. Your draft leans on 'deferred revenue' and 'recognition timing' without translating either.","task":"Write a 2-3 sentence investor-letter paragraph explaining the dynamic in plain terms.","tips":["Frame it as when cash and contracts arrive versus when rules let you count them.","The takeaway matters more than the mechanism: demand is stronger, not weaker.","Test each sentence: would a generalist investor follow it?"],"focus":["audience","clarity"],"placeholder":"Bookings grew faster than revenue this year, and that's a sign of strength:"},
    {"id":"audience-fin-senior-05","level":"senior","profession":"finance","title":"The impairment headline, explained inside","scenario":"The write-down of the 2022 acquisition puts a large one-time loss in the public results, and employees will see the headline number before lunch. You need an internal note that explains it without accounting vocabulary.","task":"Write a 3-4 sentence internal note explaining what the impairment is and isn't.","tips":["Lead with what it isn't: not cash leaving, not layoffs, not a change in the business.","Explain it as adjusting an old purchase price to reality.","Say plainly what, if anything, changes for employees: nothing."],"focus":["audience","clarity"]},
    {"id":"audience-fin-senior-06","level":"senior","profession":"finance","title":"The pre-read pitched at the wrong altitude","scenario":"Your board pre-read on the pricing change runs eleven pages of cohort analysis. Directors need two things: what you're deciding and what could go wrong. The analysis belongs underneath, not up front.","task":"Write the pre-read's opening paragraph (3-4 sentences) at board altitude: the decision, the bet, the risk.","tips":["Directors govern; they don't operate. Give them the decision shape.","One sentence each: what we're doing, why now, the main risk, what we'd watch.","Point to the analysis for those who want depth."],"focus":["audience","structure"]},
    {"id":"audience-fin-senior-07","level":"senior","profession":"finance","title":"The FX headwind for the CEO's all-hands","scenario":"The CEO asked for two sentences on the currency headwind for their all-hands script. Your first draft says constant-currency growth was 9% versus 6% reported due to euro depreciation — accurate, and useless to most of the room.","task":"Write 2 sentences the CEO can say aloud that any employee will follow.","tips":["Say it in outcomes: the business grew faster than the reported number shows.","One plain clause on why: the euro fell against the dollar.","Cut any term you'd have to define from the stage."],"focus":["audience","clarity"],"placeholder":"The business actually grew faster than the headline shows —"},
    {"id":"audience-fin-senior-08","level":"senior","profession":"finance","title":"Same numbers, lender audience","scenario":"You're adapting your investor deck for a bank meeting about extending the credit facility. The deck sells growth and market opportunity. Lenders care about different things: cash generation, covenant headroom, and what happens in a downturn.","task":"Write the 2-3 sentence opening of the bank version, reframed around what a lender needs to hear.","tips":["Lead with debt-service capacity and cash stability, not upside.","A lender's question is 'do we get paid back in the bad case?'","Keep growth as supporting evidence of durability, not the headline."],"focus":["audience","structure"]},
    {"id":"audience-fin-senior-09","level":"senior","profession":"finance","title":"The cost program for the people running it","scenario":"Middle managers must deliver the cost program: renegotiate vendors, consolidate tools, hold vacancies. Your draft note to them repeats the board framing — margin targets and investor expectations — instead of telling them what to do differently on Monday.","task":"Write a 3-4 sentence note for managers focused on their actions and decision rights.","tips":["Their question: what do I do, what can I decide, where do I escalate?","Concrete beats inspirational: name the three actions.","Board framing is one sentence of context, at most."],"focus":["audience","impact"]},
    {"id":"audience-fin-senior-10","level":"senior","profession":"finance","title":"One leverage number, two audiences","scenario":"Leverage rose to 3.1x this quarter because of the acquisition. To equity investors this is a growth story; to the rating agency it's a credit question. You're writing the two-sentence framing for each and they cannot be the same sentences.","task":"Write the 2-sentence rating-agency framing of the 3.1x number.","tips":["The agency's stake: trajectory and commitment, not opportunity.","Lead with the deleveraging path and the discipline behind it.","Same fact, different first sentence — that's audience calibration."],"focus":["audience","precision"],"placeholder":"Leverage peaked at 3.1x with the acquisition close and falls below 2.5x within four quarters under our base plan."},
    {"id":"audience-fin-senior-11","level":"senior","profession":"finance","title":"The budget that 'disappeared'","scenario":"A department head is angry that $200K 'vanished' from their budget. Nothing vanished — an annual software payment was accrued monthly this year instead of hitting one quarter. Your draft reply explains accrual accounting from first principles.","task":"Write a 2-3 sentence reply that resolves their concern in their terms.","tips":["Lead with their stake: your total budget is unchanged.","Explain the timing shift in one plain sentence, no accounting lecture.","Offer the one-line proof: same annual number, different monthly spread."],"focus":["audience","clarity"],"placeholder":"Your total budget is unchanged — the $200K moved, it didn't disappear."},
    {"id":"audience-fin-senior-12","level":"senior","profession":"finance","title":"The monthly pack for a product-minded CEO","scenario":"Your new CEO came up through product and finds the monthly finance pack unreadable — forty pages of statements and variances. They asked for something they can absorb in ten minutes that still gives them control of the business.","task":"Write a 3-4 sentence proposal describing the reframed pack, pitched at how this CEO thinks.","tips":["Anchor on the questions a CEO must answer, not the statements you produce.","Propose a first page: five numbers, each with 'what changed and why.'","Keep the full statements available, not mandatory."],"focus":["audience","structure"]},
    {"id":"audience-fin-senior-13","level":"senior","profession":"finance","title":"Same control issue, two rooms","scenario":"A payroll-access control failed and was caught by a compensating check. The audit committee needs testing detail and remediation evidence. The full board needs one paragraph: what happened, was there any loss, is it fixed. Your draft gives both rooms the deep version.","task":"Write the full-board version in 2-3 sentences.","tips":["Board altitude: impact, exposure, resolution — not test procedures.","Answer the unasked question first: no loss occurred.","Save the evidence trail for the committee that owns it."],"focus":["audience","concision"],"placeholder":"A payroll-access control failed in March; a secondary check caught it and no loss occurred."},
    {"id":"audience-fin-senior-14","level":"senior","profession":"finance","title":"The price increase, framed for customer success","scenario":"Finance modeled the 8% price increase; customer success has to defend it in renewal calls. Your draft note gives them margin math. They need something else entirely: what to say when a customer pushes back.","task":"Write a 3-4 sentence note for CS leaders focused on the customer conversation, not the finance case.","tips":["Their stake: keeping renewals while carrying the increase.","Give them the defensible 'why' in customer language — costs, product investment.","Tell them what flexibility they have and where the floor is."],"focus":["audience","impact"]},
    {"id":"audience-fin-senior-15","level":"senior","profession":"finance","title":"The buyback question at the all-hands","scenario":"The company announced a $30M share buyback the same quarter merit raises were capped at 2%. An employee asked the obvious question at the all-hands: why buy stock instead of paying us? You have thirty seconds and a skeptical room.","task":"Write a 3-4 sentence spoken answer that takes the question seriously in the employees' terms.","tips":["Don't lead with 'returning capital to shareholders' — that phrase is the problem.","Acknowledge the tension honestly before explaining the reasoning.","Separate the money's sources and rules in plain words, then say what would change raises."],"focus":["audience","clarity"]},
    {"id":"audience-fin-senior-16","level":"senior","profession":"finance","title":"Vendor consolidation for the engineers who resist it","scenario":"Procurement's consolidation plan saves $1.8M but requires engineering to migrate off two beloved tools. Your memo to engineering leadership currently leads with the savings number — the argument least likely to move them.","task":"Write a 2-3 sentence opening for engineering leaders that starts from their stake, not the savings.","tips":["Their stake: disruption, migration effort, tool quality.","Lead with what's protected and what they control in the decision.","The savings number supports; it doesn't persuade this room."],"focus":["audience","impact"]},
    {"id":"audience-fin-senior-17","level":"senior","profession":"finance","title":"Equity overhang for the comp committee","scenario":"The comp committee must approve the new equity pool, and the key constraint is dilution — the pool would push total overhang to 14%, above the level proxy advisors flag. Two committee members are unfamiliar with the term 'overhang.'","task":"Write a 3-4 sentence explanation of the constraint that works without prior vocabulary.","tips":["Define by consequence: how much of the company is promised to employees versus shareholders.","Name the practical limit: where advisors start voting against.","End with the decision this frames, not just the concept."],"focus":["audience","precision"]},
    {"id":"audience-fin-senior-18","level":"senior","profession":"finance","title":"Revenue timing for the head of sales","scenario":"The head of sales wants to pull two large deals into this quarter to 'help the number.' The deals would be signed but not deliverable until next quarter, so almost none of the revenue counts now. Your draft explains recognition criteria — to someone who stopped reading at 'criteria.'","task":"Write a 2-3 sentence reply in deal language: what the deals do and don't do for this quarter.","tips":["Answer their real question: does this help the quarter? Mostly no — and say why in one plain line.","Translate: signed isn't the same as counted; delivery is what counts.","Give them what the deals do help: next quarter, and the bookings story."],"focus":["audience","clarity"],"placeholder":"Signing them this quarter helps bookings but barely moves revenue —"},
    {"id":"audience-fin-senior-19","level":"senior","profession":"finance","title":"The email trying to serve three audiences","scenario":"Your draft announcement of the new expense policy is going to the board, all managers, and the external auditors at once — so it explains governance rationale, daily procedure, and control design in one email. It serves nobody.","task":"Choose managers as the primary audience and rewrite the opening 2-3 sentences for them alone.","tips":["One primary audience per message; the others get their own version.","Managers need: what changes, when, and what they must do.","Governance and control detail move to the board memo and audit note."],"focus":["audience","structure"]},
    {"id":"audience-fin-senior-20","level":"senior","profession":"finance","title":"The 13-week cash forecast for the exec team","scenario":"You run a 13-week cash forecast that drives real decisions, but the exec team's eyes glaze at the weekly grid. They need the decision content: when cash gets tight, what causes it, and what levers exist.","task":"Write a 3-4 sentence summary of a tight-cash forecast pitched for exec action.","tips":["Lead with the pinch point: which week, how tight.","Name the one or two drivers in operational terms.","List the levers and who owns each — that's what makes it an exec document."],"focus":["audience","structure"],"placeholder":"Cash gets tightest in the week of May 12 —"},
    {"id":"audience-fin-senior-21","level":"senior","profession":"finance","title":"Profitable but cash-poor, for the offsite","scenario":"At the leadership offsite you have ten minutes to explain a paradox that keeps surfacing: the company is profitable, yet every investment conversation ends with 'we can't afford it.' The room is smart but non-financial.","task":"Write the 3-4 sentence core of that explanation, built for a non-finance leadership audience.","tips":["Use the timing gap: profit is earned over a year; cash is needed on specific days.","Ground it in one concrete example from the business, not a generic metaphor.","End with what it means for how they should bring investment asks."],"focus":["audience","clarity"]},
    {"id":"audience-fin-senior-22","level":"senior","profession":"finance","title":"One FAQ answer, two kinds of investor","scenario":"Your IR FAQ answers 'why did operating expenses grow faster than revenue?' The current draft is written for analysts — segment mix, investment phasing. Retail shareholders read the same page and need the plain version.","task":"Write a 2-3 sentence answer a retail shareholder can follow that an analyst won't find imprecise.","tips":["Plain first: we chose to spend ahead of growth in two areas — name them.","Keep one precise anchor (the numbers) so analysts trust it.","Delete any phrase that only exists in earnings-call dialect."],"focus":["audience","precision"]},
    {"id":"audience-fin-senior-23","level":"senior","profession":"finance","title":"Capitalized engineering, explained to the CTO","scenario":"The CTO is confused and slightly suspicious: half their engineers' cost 'left the P&L' this year. It was capitalized against the new platform build — standard treatment, but it looks like an accounting trick to them.","task":"Write a 3-4 sentence explanation for the CTO that dissolves the suspicion.","tips":["Start from what they saw: the cost didn't shrink, it moved — say where and why.","Frame the logic: building an asset versus running the shop.","Name the honest catch: it comes back as depreciation — hiding nothing builds trust."],"focus":["audience","clarity"],"placeholder":"The cost didn't disappear — it moved."},
    {"id":"audience-fin-senior-24","level":"senior","profession":"finance","title":"Covenant headroom in one CEO line","scenario":"The CEO is walking into a press interview and wants one plain sentence in case financing questions come up: how much room do we have on our debt terms? You know the answer in ratios; they need it in words.","task":"Write the one sentence, plus one backup sentence, in plain CEO-speakable language.","tips":["Convert the ratio into distance: how much earnings could fall before it matters.","No covenant names, no ratio vocabulary — it must survive being quoted.","The backup sentence handles 'what if things get worse?'"],"focus":["audience","concision"]},
    {"id":"audience-fin-senior-25","level":"senior","profession":"finance","title":"'Why did executives get bonuses?'","scenario":"At the all-hands after a year of cost cuts, an employee asks why the executive team received bonuses when budgets were frozen. The legally accurate answer involves pre-set incentive formulas and board approval. Said that way, it will make things worse.","task":"Write a 3-4 sentence spoken answer that respects the room while staying truthful.","tips":["Acknowledge the fairness question directly — it's the actual question.","Explain the mechanics in one human sentence, not comp-committee language.","Say what was reduced or tied to results, if true — specifics earn back trust."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-fin-senior-01","level":"senior","profession":"finance","title":"One governing idea for the quarter","scenario":"Your board deck's executive summary lists nine observations about the quarter with no hierarchy: revenue, margin, churn, hiring, cash, pipeline, pricing, competition, systems. The quarter has a story — margin expansion funding reinvestment — but the page doesn't tell it.","task":"Write the governing idea as one sentence, then name the 3 buckets beneath it.","tips":["One idea at the top that the whole quarter supports.","Each bucket earns its place by supporting that idea.","Anything that fits no bucket goes to the appendix, not the summary."],"focus":["structure","clarity"],"placeholder":"The quarter's story: margin expansion is funding reinvestment without touching guidance. Three parts:"},
    {"id":"structure-fin-senior-02","level":"senior","profession":"finance","title":"SCQA for the guidance cut","scenario":"You're writing the memo recommending a guidance cut. You have all the pieces — the original plan, the demand shift, the choice ahead — but the draft wanders between them. SCQA would hold it: Situation, Complication, Question, Answer.","task":"Write the guidance-cut memo opening as four SCQA sentences, one per element.","tips":["Situation: the plan everyone agreed to. Complication: what changed.","The Question should be the one the board is already asking.","Your Answer is the recommendation — it lands with force because the frame earned it."],"focus":["structure","clarity"]},
    {"id":"structure-fin-senior-03","level":"senior","profession":"finance","title":"Nine cost actions, three buckets","scenario":"Your cost-program update lists nine actions in the order the team completed them: vendor renegotiation, hiring slowdown, office consolidation, tool rationalization, travel policy, contractor reduction, cloud optimization, marketing mix shift, energy contracts. The board can't see the shape of the program.","task":"Group the nine actions into 3 named buckets and write a one-line header for each.","tips":["Group by logic (people, suppliers, footprint), not chronology.","Each bucket header should carry a message, not just a label.","Test: could a director recall the three buckets an hour later?"],"focus":["structure","concision"]},
    {"id":"structure-fin-senior-04","level":"senior","profession":"finance","title":"PREP for the margin question","scenario":"On the earnings call, an analyst will ask whether the margin gains are sustainable. You know the answer is yes with one caveat, but your spoken answers tend to tour the evidence before landing anywhere. PREP — Point, Reason, Example, Point — would fix that.","task":"Write a 4-sentence PREP answer to 'are the margin gains sustainable?'","tips":["Point first: yes, the gains are structural.","One reason, one concrete example — not three of each.","Restate the point in different words to close."],"focus":["structure","clarity"],"placeholder":"Yes — the gains are structural, not timing."},
    {"id":"structure-fin-senior-05","level":"senior","profession":"finance","title":"Pyramid the capital-allocation case","scenario":"Your memo recommends paying down debt over a buyback, but it's built bottom-up: rate analysis, then EPS math, then risk scenarios, with the recommendation emerging at the end. Read top-down, it should open with the answer and descend into support.","task":"Write the top of the pyramid: the recommendation sentence and the 3 supporting arguments as one line each.","tips":["Recommendation first; each support must independently argue for it.","Three supports maximum — the fourth-best argument weakens the page.","Order supports by strength for this board, not by analytical sequence."],"focus":["structure","impact"]},
    {"id":"structure-fin-senior-06","level":"senior","profession":"finance","title":"Audit findings, grouped by theme","scenario":"The internal-audit summary for the committee lists eleven findings in the order audits were completed — access controls mixed in with expense compliance mixed in with vendor onboarding. The committee needs to see the pattern: most findings trace to unclear process ownership.","task":"Write a 2-3 sentence summary that leads with the pattern, then names the thematic groups.","tips":["The insight is the grouping: one root cause explains most findings.","Chronological listing hides exactly what the committee pays you to see.","Name each theme with its finding count so severity is visible."],"focus":["structure","clarity"],"placeholder":"Eight of the eleven findings trace to one root cause: unclear process ownership."},
    {"id":"structure-fin-senior-07","level":"senior","profession":"finance","title":"The earnings script's spine","scenario":"Your prepared remarks draft is a tour of the P&L, top to bottom, fifteen minutes long. Nobody remembers a P&L tour. The quarter supports a three-part spine: what happened, what drove it, what it means for the year.","task":"Write the three section-opening sentences — one for results, drivers, and outlook.","tips":["Each section opener should be quotable on its own.","Results get numbers; drivers get causes; outlook gets commitment level.","If a fact doesn't serve one of the three, it doesn't make the script."],"focus":["structure","impact"]},
    {"id":"structure-fin-senior-08","level":"senior","profession":"finance","title":"Untangling the CFO letter","scenario":"The results-announcement letter you drafted alternates between this year's performance, next year's plans, and reflections on the market — the same three threads braided randomly across six paragraphs. Each thread is fine; the braid is unreadable.","task":"Propose the letter's structure: 3 sections in order, one sentence each on what each contains and why that order.","tips":["Untangle by giving each thread its own section.","Order for the reader: performance earns the right to discuss plans.","Market reflections either serve a section or get cut."],"focus":["structure","clarity"]},
    {"id":"structure-fin-senior-09","level":"senior","profession":"finance","title":"Ordering the bank meeting","scenario":"You have forty-five minutes with three lenders to make the case for extending the facility on better terms. Your instinct is to open with the growth story. But the argument that actually persuades lenders has its own order: track record, cash generation, downside resilience, then the ask.","task":"Write the meeting's 4-part agenda with a one-line message per part, in persuasive order.","tips":["Sequence for their decision logic, not your enthusiasm.","Each part should close a question the next part builds on.","Put the ask last but signal it first, so the evidence has a destination."],"focus":["structure","audience"]},
    {"id":"structure-fin-senior-10","level":"senior","profession":"finance","title":"Three scenarios, one page","scenario":"The board asked for downside planning. Your draft presents base, downside, and severe cases as three separate narratives, forcing directors to build their own comparison. The page should be structured around what changes across scenarios, not three stories.","task":"Write the one-page structure: the framing sentence and the 3-4 comparison rows you'd organize it around.","tips":["Structure by variable (revenue, cash, covenant headroom, actions), not by scenario.","Lead with the framing: what has to be true for each case.","The 'actions' row is the payoff — same triggers visible across all three."],"focus":["structure","precision"]},
    {"id":"structure-fin-senior-11","level":"senior","profession":"finance","title":"Variance commentary by driver","scenario":"Your monthly commentary explains the $2.1M expense variance line by line: salaries, software, travel, facilities, marketing. The real story crosses those lines — one driver (delayed backfills) explains more than half. Line-item order buries causal order.","task":"Rewrite the commentary opening in 2-3 sentences organized by driver, largest first.","tips":["Group by cause: what happened, not where it landed in the ledger.","Quantify each driver's share so the hierarchy is explicit.","Line-item detail survives as a table beneath the narrative."],"focus":["structure","precision"],"placeholder":"More than half the $2.1M favorable variance comes from one driver: delayed backfills."},
    {"id":"structure-fin-senior-12","level":"senior","profession":"finance","title":"Twenty questions, four themes","scenario":"Your team's earnings Q&A prep doc lists twenty anticipated questions in random order, each with a standalone answer. On the call you'll get variations, not exact matches — what you need is themes with a core message each, so any variant maps to a prepared position.","task":"Name 4 themes the twenty questions collapse into and write the one-line core message for each.","tips":["Themes should cover variants: 'margin sustainability' catches ten phrasings.","One core message per theme keeps answers consistent under pressure.","The doc's structure is the prep — random lists don't survive live Q&A."],"focus":["structure","clarity"]},
    {"id":"structure-fin-senior-13","level":"senior","profession":"finance","title":"One idea per diligence section","scenario":"Your diligence readout on the target has sections titled 'Financials,' 'Contracts,' and 'Operations' — labels, not messages. Each section actually has a conclusion: earnings quality is weaker than reported; contracts concentrate risk; operations are the hidden asset.","task":"Rewrite the 3 section titles as message headlines and add one supporting line under each.","tips":["A section title should state the section's conclusion.","If a reader only reads headlines, they should get your full assessment.","Message titles force you to decide what each section proves."],"focus":["structure","impact"],"placeholder":"1. Reported earnings overstate run-rate quality —"},
    {"id":"structure-fin-senior-14","level":"senior","profession":"finance","title":"Three things to remember","scenario":"Your all-hands finance segment covers the quarter in twelve slides. Employees will remember almost none of it. You decide to open by naming the only three things you want the company to retain — and let every slide serve one of them.","task":"Write the spoken opening: 'Three things to remember' plus the three, one sentence each.","tips":["Choose the three for the audience: what should change how they work?","Announce the structure — it tells people how to listen.","Every slide that serves none of the three gets cut."],"focus":["structure","audience"]},
    {"id":"structure-fin-senior-15","level":"senior","profession":"finance","title":"The acquisition case, top-down","scenario":"You're presenting the acquisition to the investment committee. The team's draft walks through the target company's history, then the market, then the model, arriving at the recommendation in minute eighteen. Committees decide in the first five minutes and spend the rest confirming.","task":"Write the opening minute: recommendation, price logic, and the 3 pillars of the case, in that order.","tips":["Verdict first: buy, at what price, expecting what return.","Three pillars, one sentence each — the deep dive follows.","Structure the talk so early interruptions still leave your case intact."],"focus":["structure","impact"]},
    {"id":"structure-fin-senior-16","level":"senior","profession":"finance","title":"Grouping the risk register","scenario":"The board pack's risk section lists fourteen risks alphabetically, from 'competitor pricing' to 'vendor concentration.' Alphabetical order treats a company-threatening risk and an annoyance identically. The section needs a structure that carries judgment.","task":"Propose the structure in 2-3 sentences: how you'd group and order the fourteen risks, and what the top of the section says.","tips":["Group by severity-and-movement: what's new, what's grown, what's stable.","Lead with the two or three risks that deserve board time.","A risk section's structure is itself a statement of judgment."],"focus":["structure","clarity"]},
    {"id":"structure-fin-senior-17","level":"senior","profession":"finance","title":"SCQA for the ERP investment","scenario":"You're asking the board for $6M for the ERP replacement. The draft leads with vendor selection detail. The persuasive frame is SCQA: the company runs on a system built for half its size (S), close cycles and error rates are degrading (C), invest now or patch again (Q), replace now (A).","task":"Write the four SCQA sentences for the ERP request.","tips":["Make the Complication concrete: what broke, what it cost.","The Question must present a real choice, not a rhetorical one.","The Answer includes the number and the timeline — it's an ask, not a theme."],"focus":["structure","impact"]},
    {"id":"structure-fin-senior-18","level":"senior","profession":"finance","title":"PREP for 'why not buy back stock?'","scenario":"At an investor lunch, someone will ask why you're not buying back stock at these prices. You have a good answer — the debt paydown earns more risk-adjusted — but delivered as a wandering discussion it sounds like an excuse.","task":"Write a 4-sentence PREP answer: Point, Reason, Example, Point.","tips":["Point: we get a better return retiring debt at today's rates.","The example makes it concrete: the actual rate comparison.","Closing restatement signals conviction, not defensiveness."],"focus":["structure","clarity"],"placeholder":"Right now, paying down debt beats buying back stock —"},
    {"id":"structure-fin-senior-19","level":"senior","profession":"finance","title":"The cash bridge as narrative","scenario":"Your board slide shows opening cash to closing cash through seven bars: EBITDA, working capital, capex, interest, tax, one-offs, FX. The chart is fine; the narration is a list. A bridge should be told as a story with a shape: what generated, what consumed, what remains.","task":"Write a 3-sentence narration of the bridge that gives it narrative shape rather than listing the bars.","tips":["Group the bars into generation and consumption before narrating.","Name the one bar the board should interrogate.","End at the destination: what the closing position enables or constrains."],"focus":["structure","clarity"]},
    {"id":"structure-fin-senior-20","level":"senior","profession":"finance","title":"Restructuring the budget kickoff","scenario":"Your budget kickoff deck has grown to thirty slides accreted over five annual cycles — instructions, templates, macro outlook, last year's lessons, timeline, targets, in no particular order. Leaders leave the kickoff unclear on the three things that matter: target, process, deadline.","task":"Propose a 3-part structure for the deck in 3 sentences, one per part with its core message.","tips":["Structure around the leader's needs: what number, what steps, what date.","Everything else is reference material, linked not presented.","Sequence so each part answers the question the previous part raises."],"focus":["structure","concision"]},
    {"id":"structure-fin-senior-21","level":"senior","profession":"finance","title":"Decisions, discussions, follow-ups","scenario":"Your post-board summary email to the exec team recaps the meeting chronologically — agenda item by agenda item. Executives reading it can't quickly find what was decided versus merely discussed, or what they now owe.","task":"Rewrite the summary's structure: 3 headed sections with one example line under each.","tips":["Decided, discussed, and owed are different kinds of information — separate them.","Under 'decisions,' state each as done: approved, rejected, deferred.","Follow-ups get an owner and a date or they aren't follow-ups."],"focus":["structure","clarity"],"placeholder":"DECIDED: Credit facility approved as presented."},
    {"id":"structure-fin-senior-22","level":"senior","profession":"finance","title":"Progress, risks, asks","scenario":"Your monthly cost-program update to the steering committee is a wall of status prose. The committee needs three things in fixed positions every month: where the program stands, what threatens it, and what you need from them. A repeated structure builds reading speed.","task":"Write this month's update in the 3-part frame: one or two sentences per part.","tips":["Fixed structure across months lets readers compare instantly.","'Asks' is the section that makes the update useful — never leave it empty or vague.","Quantify progress against the same baseline every time."],"focus":["structure","concision"]},
    {"id":"structure-fin-senior-23","level":"senior","profession":"finance","title":"Pyramiding the controller's email","scenario":"Your controller sent you a long, careful email about a tax exposure — background, statute detail, correspondence history, and somewhere in paragraph five, the point: likely liability of $300-500K, position defensible, provision recommended. You're forwarding it to the CEO and can't send it as is.","task":"Write the 3-sentence top you'd add above the forwarded email: conclusion, size, recommended action.","tips":["Your cover note is the pyramid top; the forward is the support.","The CEO should need only your three sentences.","Keep the controller's caution but not their sequence."],"focus":["structure","clarity"],"placeholder":"Bottom line: we likely owe $300-500K on a state tax position —"},
    {"id":"structure-fin-senior-24","level":"senior","profession":"finance","title":"The rating-agency storyline","scenario":"Your rating-agency presentation inherited the investor deck's structure: market, product, growth, financials. Agencies read in a different order — they start from the balance sheet and work outward. The same slides need a different storyline.","task":"Write the 4-part storyline for the agency version, one message sentence per part.","tips":["Open where their analysis starts: leverage, liquidity, coverage.","Business quality becomes evidence for credit durability, not a growth pitch.","Close with the financial-policy commitments — the part agencies quote back."],"focus":["structure","audience"]},
    {"id":"structure-fin-senior-25","level":"senior","profession":"finance","title":"The integration update's shape","scenario":"Six months post-acquisition, your board update on integration covers synergies, systems, people, and customers in a status-report sprawl. The governing question the board holds is simpler: is the deal delivering the model we approved? Structure should answer that question first.","task":"Write the update's opening sentence (the verdict against the deal model) and the 3 section headers beneath it.","tips":["Lead with performance against the approved deal model — that's the contract with the board.","Sections as messages: ahead, on track, behind — with the item named.","Status detail hangs off the verdict, never the reverse."],"focus":["structure","impact"],"placeholder":"Six months in, the deal is tracking at 90% of the model we approved —"}
  ],
  "cut-to-the-bone": [
    {"id":"concise-fin-senior-01","level":"senior","profession":"finance","title":"The hedged guidance paragraph","scenario":"Your draft guidance commentary reads: 'We currently believe that, subject to prevailing conditions, revenue could potentially be in the general range of what we might describe as broadly flat to modestly up.' The board can't tell what you're actually saying.","task":"Rewrite this as one clear sentence with a real range.","tips":["Every hedge you stack subtracts credibility — pick one range and commit.","'Currently believe,' 'potentially,' 'could' are three hedges doing one job.","A number with a caveat beats a paragraph of qualifiers."],"focus":["concision","precision"],"placeholder":"We expect revenue flat to up 3%, with the risk weighted to the downside."},
    {"id":"concise-fin-senior-02","level":"senior","profession":"finance","title":"The nominalized cost memo","scenario":"Your cost-program memo is thick with nominalizations: 'the implementation of a reduction in discretionary expenditure,' 'the utilization of vendor renegotiation as a mechanism for the achievement of savings.' Buried under the abstractions are simple actions.","task":"Rewrite these two phrases as plain verb-driven sentences.","tips":["Turn nouns back into verbs: 'reduce spending,' 'renegotiate vendors to save.'","Nominalizations hide who does what — restore the actor and the action.","If a sentence has no live verb, it isn't a sentence yet."],"focus":["concision","clarity"]},
    {"id":"concise-fin-senior-03","level":"senior","profession":"finance","title":"Halve the board risk paragraph","scenario":"Your board risk narrative runs 140 words to make one point: customer concentration has risen and you're diversifying. It circles the point three times with slightly different phrasing before arriving.","task":"Cut it to under 50 words without losing the risk or the response.","tips":["Say the risk once, in its strongest form, then stop.","Delete the two restatements — they add words, not weight.","One sentence of risk, one of response, is often the whole job."],"focus":["concision","impact"]},
    {"id":"concise-fin-senior-04","level":"senior","profession":"finance","title":"The meta-commentary in the CFO letter","scenario":"Your results letter opens with a paragraph about the letter: 'In this letter I will walk you through our performance, provide context on the drivers, and share my perspective on the outlook.' The reader wanted the performance, not the table of contents.","task":"Cut the meta-commentary and write the real opening sentence instead.","tips":["Don't announce what you'll say — say it.","'I will walk you through' is throat-clearing; delete the whole sentence.","The best opening does the thing the meta-paragraph promised."],"focus":["concision","impact"],"placeholder":"Revenue grew 11% and operating margin expanded two points —"},
    {"id":"concise-fin-senior-05","level":"senior","profession":"finance","title":"Redundant pairs in the audit note","scenario":"Your audit-committee note is full of doubled phrases: 'accurate and correct,' 'review and examine,' 'each and every,' 'full and complete.' Each pair says one thing twice, and together they make the note read as padded.","task":"Rewrite three sentences from the note, cutting the redundant pairs to single words.","tips":["Pick the stronger word of each pair and drop the other.","Doubled phrases signal filler to a skeptical committee.","'Complete' already means full; 'examine' already means review."],"focus":["concision","precision"]},
    {"id":"concise-fin-senior-06","level":"senior","profession":"finance","title":"The buried number in the variance line","scenario":"Your variance commentary reads: 'It is worth noting that there was a somewhat notable degree of overperformance relative to our expectations in the area of gross margin.' The actual fact — margin beat by 180 basis points — never appears.","task":"Rewrite as one sentence that leads with the number.","tips":["'It is worth noting' notes nothing — cut it.","Replace 'somewhat notable degree' with the basis points.","A vague intensifier where a number belongs is a tell."],"focus":["concision","precision"],"placeholder":"Gross margin beat plan by 180 basis points."},
    {"id":"concise-fin-senior-07","level":"senior","profession":"finance","title":"The over-qualified recommendation","scenario":"Your capital memo's recommendation reads: 'While there are certainly arguments on both sides and reasonable people could disagree, on balance and all things considered, we would tentatively lean toward suggesting we might consider debt paydown.' The board can't find the recommendation inside the hedging.","task":"Rewrite as a single confident recommendation sentence.","tips":["A recommendation buried in six hedges isn't a recommendation.","Keep one honest caveat if it's real; delete the ritual ones.","'We recommend debt paydown' — then defend it, don't pre-apologize."],"focus":["concision","impact"],"placeholder":"We recommend directing excess cash to debt paydown this year."},
    {"id":"concise-fin-senior-08","level":"senior","profession":"finance","title":"The filler in the earnings script","scenario":"Your earnings remarks are padded with verbal filler: 'As you know,' 'needless to say,' 'at the end of the day,' 'from a financial perspective.' On a fifteen-minute call, these phrases cost you thirty seconds and dilute every sentence they touch.","task":"Rewrite a three-sentence passage from the script with all filler removed.","tips":["'As you know' — then don't say it. 'Needless to say' — then don't.","'From a financial perspective' is redundant coming from the CFO.","Read it aloud; every phrase that adds no fact goes."],"focus":["concision","impact"]},
    {"id":"concise-fin-senior-09","level":"senior","profession":"finance","title":"The 400-word answer that needed 40","scenario":"An investor asked whether you'd consider a dividend. Your draft reply spends four paragraphs on capital-allocation philosophy before the answer: not this year, reinvestment comes first. The philosophy buries the answer.","task":"Write the 40-word version that answers first, then justifies.","tips":["Answer the question in the first clause: not this year.","One reason is enough support for a clear no.","Cut the philosophy tour — offer it only if they ask."],"focus":["concision","clarity"],"placeholder":"Not this year — we're prioritizing reinvestment while returns on capital stay above our cost of capital."},
    {"id":"concise-fin-senior-10","level":"senior","profession":"finance","title":"Trimming the covenant email","scenario":"Your email to the lender about a covenant waiver is 300 words, and 200 of them recap history the banker already knows. The ask and the terms — the only new information — are two sentences lost in the middle.","task":"Cut the email to its essential 3-4 sentences: the ask, the terms, the timeline.","tips":["The banker lived the history — don't recap what they know.","Lead with the new information: what you're asking and by when.","Attach the detail; keep the email to the decision."],"focus":["concision","clarity"]},
    {"id":"concise-fin-senior-11","level":"senior","profession":"finance","title":"The all-hands slide with nine bullets","scenario":"Your all-hands finance slide has nine bullets, each a full sentence, covering every metric that moved. The room retains none of it. The quarter has one message worth their attention.","task":"Cut the nine bullets to one headline plus at most three supporting points.","tips":["Nine bullets means no priority — choose the one that matters.","A bullet should be a phrase, not a sentence, on a slide.","What you cut is what makes the rest memorable."],"focus":["concision","impact"]},
    {"id":"concise-fin-senior-12","level":"senior","profession":"finance","title":"The throat-clearing in the CEO update","scenario":"Your weekly update to the CEO opens: 'I wanted to take a moment to reach out and provide you with a brief update regarding where things stand with respect to our cash position.' Fifteen words before any content.","task":"Rewrite the opening so the first word carries information.","tips":["'I wanted to reach out to update you' — the CEO knows why you're writing.","Delete the frame; start with the cash number.","Every word before the first fact is a word the CEO forgives but doesn't need."],"focus":["concision","impact"],"placeholder":"Cash is $42M, up $3M this week on the collections push."},
    {"id":"concise-fin-senior-13","level":"senior","profession":"finance","title":"The bloated scenario caveat","scenario":"Your downside scenario is wrapped in 80 words of caveats about forecasting uncertainty before it presents a single number. The board asked for the downside case, not a disclaimer.","task":"Replace the 80-word caveat with a single honest sentence, then get to the numbers.","tips":["One sentence of appropriate humility; the rest is defensiveness.","The board knows forecasts are uncertain — you don't need to prove it.","Front-load the numbers; caveat the specific assumption that's shakiest."],"focus":["concision","precision"]},
    {"id":"concise-fin-senior-14","level":"senior","profession":"finance","title":"The passive-voice control finding","scenario":"Your remediation memo reads: 'It was determined that an error had been made in the reconciliation process, and it has since been addressed by the relevant team.' Nobody owns anything; nothing is concrete.","task":"Rewrite in active voice naming who did what.","tips":["Passive voice hides the actor — the committee wants to know who.","'The team found a reconciliation error and fixed it' — three facts, half the words.","Own the finding; evasive grammar reads as evasion."],"focus":["concision","clarity"],"placeholder":"The controller's team found a reconciliation error in March and corrected it within the week."},
    {"id":"concise-fin-senior-15","level":"senior","profession":"finance","title":"The redundant capital-structure recap","scenario":"Your financing memo restates the current capital structure three times — in the intro, in the analysis, and in the recommendation — each time in full. The repetition triples the length without adding information.","task":"Consolidate to a single statement of the capital structure, placed once.","tips":["State the facts once, in the right place, and reference them after.","Repetition for emphasis works for a message, not for a data recap.","Cut two of the three; the memo loses nothing."],"focus":["concision","structure"]},
    {"id":"concise-fin-senior-16","level":"senior","profession":"finance","title":"The 25-word sentence that needs a period","scenario":"Your risk disclosure contains a single sentence running 60 words, chaining five clauses with commas and 'which' and 'thereby.' By the end, the reader has lost the beginning.","task":"Break it into 2-3 short sentences, each carrying one idea.","tips":["One idea per sentence; a period is free and clarifying.","'Which' and 'thereby' are places the sentence should have ended.","If you run out of breath reading it aloud, split it."],"focus":["concision","clarity"]},
    {"id":"concise-fin-senior-17","level":"senior","profession":"finance","title":"The over-explained obvious","scenario":"Your board memo spends a paragraph explaining why lower interest expense is good — to a board that has run companies for decades. The explanation insults the reader and pads the memo.","task":"Cut the explanation to a single stated fact and trust the reader.","tips":["Directors know why lower interest is good — just state the reduction.","Explaining the obvious signals you don't know your audience.","Save the words for what actually needs explaining."],"focus":["concision","audience"]},
    {"id":"concise-fin-senior-18","level":"senior","profession":"finance","title":"The wandering voicemail","scenario":"You're leaving your largest investor a voicemail about tomorrow's announcement. Your practice run rambled for ninety seconds, restating the news three ways and thanking them twice. A voicemail should be tight.","task":"Write a 3-sentence voicemail: the news, the one reason, the callback.","tips":["Voicemail is unforgiving of filler — every sentence earns its place.","Say the news once, clearly; don't rephrase it for safety.","One reason, one callback line, done."],"focus":["concision","impact"],"placeholder":"This is a heads-up that we're revising full-year guidance tomorrow at market open —"},
    {"id":"concise-fin-senior-19","level":"senior","profession":"finance","title":"The synergy slide's word soup","scenario":"Your integration slide describes synergies as 'the realization of operational efficiencies through the strategic optimization of overlapping functional capabilities.' Beneath the abstraction is a simple fact: you're merging two finance teams and saving $2M.","task":"Rewrite the phrase as a plain statement of what happens and what it saves.","tips":["Name the concrete action: merge the two finance teams.","Attach the number: $2M in annual savings.","Consultant-speak on a board slide reads as hiding the ball."],"focus":["concision","clarity"],"placeholder":"We're merging the two finance teams, saving $2M a year."},
    {"id":"concise-fin-senior-20","level":"senior","profession":"finance","title":"Cutting the qualifier chain from the outlook","scenario":"Your outlook statement has a qualifier chain: 'assuming no material change in macro conditions, absent any unforeseen events, and barring significant shifts in customer behavior, we anticipate...' Three qualifiers do the work one would.","task":"Keep the single most material qualifier and cut the rest.","tips":["Pick the qualifier that's actually load-bearing for this forecast.","Generic 'unforeseen events' protects against nothing — cut it.","One honest condition beats three ritual ones."],"focus":["concision","precision"]},
    {"id":"concise-fin-senior-21","level":"senior","profession":"finance","title":"The pre-read that repeats the deck","scenario":"Your board pre-read summarizes the deck, then the deck repeats the pre-read, then your talking points repeat both. Directors read the same content three times in three formats.","task":"Write a 3-sentence pre-read that adds what the deck can't: your judgment on the one decision.","tips":["A pre-read should orient, not duplicate — give them the lens.","State the decision and your recommendation; the deck has the analysis.","If the pre-read is just the deck in prose, it's waste."],"focus":["concision","structure"]},
    {"id":"concise-fin-senior-22","level":"senior","profession":"finance","title":"The 'in order to' epidemic","scenario":"Your financing proposal uses 'in order to' eleven times, 'due to the fact that' four times, and 'in the event that' six times. Each is a three-word phrase where one word works.","task":"Rewrite a paragraph replacing these phrases with 'to,' 'because,' and 'if.'","tips":["'In order to' is always just 'to.'","'Due to the fact that' is 'because.' 'In the event that' is 'if.'","These substitutions cut length and read cleaner instantly."],"focus":["concision","clarity"]},
    {"id":"concise-fin-senior-23","level":"senior","profession":"finance","title":"Trimming the investor Q&A answer","scenario":"Preparing for the call, your drafted answer on capex runs 200 words and mentions six projects, three timelines, and two philosophies. The analyst asked one thing: is capex peaking? The answer is yes, next year.","task":"Cut the answer to under 40 words that answer the actual question.","tips":["Answer the binary first: yes, capex peaks next year.","Six projects is detail for a follow-up, not the answer.","On a call, a tight answer signals command; a long one signals uncertainty."],"focus":["concision","clarity"],"placeholder":"Yes — capex peaks next year, then steps down as the platform build completes."},
    {"id":"concise-fin-senior-24","level":"senior","profession":"finance","title":"The bloated cost-freeze announcement","scenario":"Your company-wide note announcing the discretionary spend freeze is 500 words: rationale, context, reassurance, process, exceptions, and gratitude. Employees need to know three things: what's frozen, for how long, and how to request an exception.","task":"Cut the note to under 120 words covering only what employees must act on.","tips":["Lead with the action: what's frozen, effective when.","One line of why; skip the reassurance essay.","Exceptions process in one sentence; that's the part they'll actually use."],"focus":["concision","audience"]},
    {"id":"concise-fin-senior-25","level":"senior","profession":"finance","title":"The overstuffed board appendix reference","scenario":"Your board memo's key paragraph is interrupted three times by parenthetical cross-references: '(see appendix C, page 14),' '(as detailed in the model, tab 3),' '(consistent with prior guidance, Q1 deck).' The interruptions fracture the argument.","task":"Rewrite the paragraph with the references consolidated at the end, so the argument reads cleanly.","tips":["Let the argument run uninterrupted; collect references after.","Parentheticals mid-sentence force the reader to context-switch.","One 'details in the appendix' line replaces three interruptions."],"focus":["concision","structure"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-fin-senior-01","level":"senior","profession":"finance","title":"'Significantly improved' — by how much?","scenario":"Your board narrative says cash conversion 'significantly improved' and collections are 'much better than last quarter.' Directors who govern by numbers can't tell whether that's a rounding error or a turnaround.","task":"Rewrite both claims with the actual figures and the comparison period.","tips":["Replace every intensifier with a number: 'significantly' means what percent?","Anchor to a baseline: better than what, by how much.","A director should be able to verify your claim against the pack."],"focus":["precision","clarity"],"placeholder":"Cash conversion rose from 78% to 92% quarter over quarter; collections improved DSO by 6 days."},
    {"id":"precision-fin-senior-02","level":"senior","profession":"finance","title":"From the data to the one insight","scenario":"Your slide shows twelve months of margin data across four product lines — 48 data points. The board doesn't need the grid; they need the one insight it contains: one product line is dragging the blended margin down.","task":"Write the single insight sentence the data supports, with the number that proves it.","tips":["Data isn't insight — state what the reader should conclude.","One line, one number, one implication.","The grid becomes backup for the sentence, not the message."],"focus":["precision","impact"],"placeholder":"One product line, at 22% margin versus 41% blended, explains the entire margin decline."},
    {"id":"precision-fin-senior-03","level":"senior","profession":"finance","title":"What, so what, now what for the cash miss","scenario":"Cash came in $4M below forecast. Your draft note states the miss and stops there — 'what' with no 'so what' or 'now what.' The CEO is left to figure out whether it matters and what happens next.","task":"Write a 3-sentence note covering the fact, its consequence, and your action.","tips":["What: the $4M miss and its cause. So what: the effect on runway or covenants.","Now what: the specific action you're taking and by when.","A bare number invites panic; a number with a plan invites confidence."],"focus":["precision","structure"],"placeholder":"Cash landed $4M below forecast on slower collections; this shortens runway by two weeks, still within covenant."},
    {"id":"precision-fin-senior-04","level":"senior","profession":"finance","title":"Passing the skeptic test on synergies","scenario":"Your acquisition memo claims '$20M of synergies.' A skeptical director will ask: gross or net, over what period, how confident, and what's the cost to achieve. Your draft answers none of these, so the number reads as aspirational.","task":"Rewrite the synergy claim to survive the four skeptic questions.","tips":["Specify gross versus net, and the timeframe to realize.","Attach a confidence band and the cost-to-achieve.","A number that anticipates the skeptic's questions is a number they trust."],"focus":["precision","impact"],"placeholder":"$20M gross annual synergies (roughly $14M net of $6M one-time cost), phased over 18 months, with $12M high-confidence."},
    {"id":"precision-fin-senior-05","level":"senior","profession":"finance","title":"The vague forecast confidence","scenario":"Your reforecast note says you're 'fairly confident' in the revised numbers and the range is 'reasonable.' The board needs to know how much to rely on the forecast, and 'fairly' tells them nothing actionable.","task":"Replace the vague confidence language with a specific range and the assumption it hinges on.","tips":["Confidence is a range, not an adjective: give the high and low.","Name the one assumption that moves the number most.","'Fairly confident' could mean 60% or 90% — say which."],"focus":["precision","clarity"]},
    {"id":"precision-fin-senior-06","level":"senior","profession":"finance","title":"The unsubstantiated 'industry-leading'","scenario":"Your investor deck calls the company's margins 'industry-leading' and its growth 'best-in-class.' An analyst will ask against which peers and which metric. Without the comparison, the claims read as marketing.","task":"Rewrite one claim with the specific peer set and the metric that backs it.","tips":["'Industry-leading' needs the industry and the ranking to be credible.","Name the peer set and the percentile or specific comparison.","Analysts discount adjectives and reward verifiable comparisons."],"focus":["precision","audience"],"placeholder":"Our 41% operating margin is the highest among the eight peers in our proxy comparison group."},
    {"id":"precision-fin-senior-07","level":"senior","profession":"finance","title":"Dating the covenant timeline","scenario":"Your covenant risk note says the breach could happen 'in the coming quarters' if 'current trends continue.' The board needs to know which quarter and which trend, or they can't judge the urgency.","task":"Rewrite with the specific quarter, the threshold, and the trend that drives it.","tips":["'Coming quarters' hides the timeline — name the quarter.","State the ratio, the threshold, and the current distance.","Specificity converts a vague worry into a governable risk."],"focus":["precision","clarity"],"placeholder":"If EBITDA lands at the low end, leverage hits 4.1x in Q3 — above the 4.0x covenant."},
    {"id":"precision-fin-senior-08","level":"senior","profession":"finance","title":"The margin bridge without magnitudes","scenario":"Your margin walk lists the drivers — 'pricing helped, mix hurt, costs were mixed' — with no magnitudes. The board can see the direction but not the size, so they can't tell which driver deserves attention.","task":"Rewrite the bridge naming each driver's basis-point contribution.","tips":["Direction without magnitude isn't a bridge — attach the basis points.","Order the drivers by size so the biggest lever is obvious.","'Mixed' is not a number; decompose it."],"focus":["precision","structure"],"placeholder":"Pricing added 150bps, mix cost 90bps, and net cost inflation cost 30bps —"},
    {"id":"precision-fin-senior-09","level":"senior","profession":"finance","title":"The evidence gap in the cost claim","scenario":"You tell the board the cost program is 'on track.' A director asks for evidence. Your draft repeats 'on track' with more emphasis rather than pointing to the actioned dollars, the run-rate, and the timeline.","task":"Rewrite 'on track' as an evidence-backed status with three specific proof points.","tips":["'On track' is a claim; the board wants the evidence beneath it.","Proof points: dollars actioned, run-rate achieved, milestones hit.","Let the numbers say 'on track' so you don't have to."],"focus":["precision","impact"]},
    {"id":"precision-fin-senior-10","level":"senior","profession":"finance","title":"The rounding that hides the story","scenario":"Your summary rounds everything to the nearest ten million: 'revenue about $410M, costs around $350M, roughly $60M profit.' The precision the board needs — the margin moved 40 basis points — vanishes in the rounding.","task":"Present the same figures at a precision that preserves the actual movement.","tips":["Round to a level that keeps the signal, not just the headline.","If the story is 40 basis points, don't round away 40 basis points.","Match precision to the decision, not to what looks tidy."],"focus":["precision","clarity"]},
    {"id":"precision-fin-senior-11","level":"senior","profession":"finance","title":"The 'we think' investor answer","scenario":"An investor asked about your cash-return plans. Your draft answer says 'we think there's room and we're comfortable with our position' — all posture, no numbers. Investors want the specifics: how much capacity, what constraints.","task":"Rewrite with the actual capital-return capacity and the constraint that bounds it.","tips":["'Comfortable' is a feeling; give them the free-cash-flow number.","Name the constraint: leverage target, investment needs, covenant.","Precise capacity plus honest constraint reads as command."],"focus":["precision","audience"],"placeholder":"We'll generate roughly $50M of free cash flow this year; after $30M of committed investment, that leaves $20M for capital return."},
    {"id":"precision-fin-senior-12","level":"senior","profession":"finance","title":"What / so what for the DSO trend","scenario":"Your ops-review slide shows DSO rose from 45 to 52 days. That's the 'what.' You stop there, leaving the room to guess the 'so what' — that's $6M of cash tied up — and the 'now what' — the collections push starting Monday.","task":"Write the 3-part narration: the trend, its cash impact, your action.","tips":["Convert the days into dollars — that's the so-what the room feels.","State the action and its owner as the now-what.","A trend line without consequence and action is just a chart."],"focus":["precision","structure"],"placeholder":"DSO rose 7 days to 52, tying up about $6M in cash; we're launching a targeted collections push Monday."},
    {"id":"precision-fin-senior-13","level":"senior","profession":"finance","title":"The skeptic test on the growth guide","scenario":"Your guidance memo projects 15% growth. A skeptical board member will ask: how much is price, how much is volume, how much is already contracted. Your draft gives one blended number that can't withstand the decomposition.","task":"Rewrite the growth guide decomposed into price, volume, and contracted-versus-new.","tips":["A blended growth number invites the 'how much is real' question — pre-empt it.","Split price from volume; both matter to durability.","State how much is already booked versus still to win."],"focus":["precision","impact"],"placeholder":"Of the 15% guide, 4 points are price, 11 are volume, and 9 of the 15 are already contracted."},
    {"id":"precision-fin-senior-14","level":"senior","profession":"finance","title":"The imprecise write-down explanation","scenario":"Your note on the impairment says the asset was written down 'substantially' because it 'underperformed expectations by a wide margin.' The audit committee needs the carrying value, the recoverable amount, and the charge — actual numbers.","task":"Rewrite with the carrying value, the new value, and the resulting charge.","tips":["'Substantially' and 'wide margin' are placeholders for numbers you have.","Give carrying value, recoverable value, and the difference.","The committee reconciles to the accounts — vague language fails there."],"focus":["precision","clarity"]},
    {"id":"precision-fin-senior-15","level":"senior","profession":"finance","title":"One number that carries the quarter","scenario":"The exec team asked for the single metric that best captures the quarter's health. Your draft lists eight KPIs. The discipline of precision is choosing the one — free cash flow conversion — and defending why it's the right lens.","task":"Name the one metric, state its value, and justify why it's the right one in 2-3 sentences.","tips":["Precision includes selection: which number matters most, and why.","State the metric's value and its trend in one clause.","Defend the choice — why this over the obvious alternatives."],"focus":["precision","impact"]},
    {"id":"precision-fin-senior-16","level":"senior","profession":"finance","title":"The vague 'headwinds' in the outlook","scenario":"Your outlook cites 'macro headwinds' and 'a challenging demand environment' without quantifying either. The board can't calibrate the outlook against language that could describe a mild slowdown or a recession.","task":"Rewrite naming the specific headwind and its estimated impact on the numbers.","tips":["'Headwinds' is weather, not analysis — name the specific factor.","Estimate the impact: how many points of growth does it cost you?","Specific and bounded beats ominous and vague."],"focus":["precision","clarity"],"placeholder":"We expect softer enterprise demand to cost roughly 2 points of growth, concentrated in the second half."},
    {"id":"precision-fin-senior-17","level":"senior","profession":"finance","title":"The evidence behind 'the model is conservative'","scenario":"You keep telling the board the acquisition model is 'conservative,' but you haven't shown why. A director wants evidence: what assumptions did you haircut, and by how much, versus the target's own plan.","task":"Rewrite 'conservative' as three specific, quantified conservatism choices.","tips":["'Conservative' is a claim that needs receipts.","Show the specific haircuts: revenue synergies at 60% of target's plan, etc.","Quantified conservatism is credible; asserted conservatism is not."],"focus":["precision","impact"]},
    {"id":"precision-fin-senior-18","level":"senior","profession":"finance","title":"The 'a few' that hides the count","scenario":"Your update says 'a few large customers slipped their renewals' and 'several projects are behind.' The CEO needs the counts and the dollar exposure, not indefinite quantifiers.","task":"Rewrite with the exact customer count, the revenue at risk, and the project count.","tips":["'A few' and 'several' are hiding numbers you know — say them.","Attach the dollar figure to the count.","Indefinite quantifiers read as either sloppiness or softening — avoid both."],"focus":["precision","clarity"],"placeholder":"Three customers, together $8M of ARR, slipped their renewals; two integration projects are a month behind."},
    {"id":"precision-fin-senior-19","level":"senior","profession":"finance","title":"Turning the sensitivity table into a sentence","scenario":"Your board slide is a sensitivity table showing profit across nine combinations of price and volume assumptions. The board doesn't need to read the grid; they need the takeaway: profit is far more sensitive to volume than price.","task":"Write the one-sentence insight the sensitivity table proves, with the magnitude.","tips":["A sensitivity table's job is one sentence — write that sentence.","State which variable dominates and by how much.","The grid is the evidence; the sentence is the point."],"focus":["precision","impact"],"placeholder":"A 5% volume miss costs three times more profit than a 5% price miss — volume is the number to watch."},
    {"id":"precision-fin-senior-20","level":"senior","profession":"finance","title":"The unsourced peer comparison","scenario":"Your financing deck claims 'our terms are better than market.' The banker will ask which deals, which terms, which period. Without the comparable transactions, the claim is just a negotiating posture.","task":"Rewrite the claim citing the specific comparable deals and the terms that beat them.","tips":["'Better than market' needs the market: which recent deals, what terms.","Cite two or three comparables with the specific spread or covenant.","Bankers respect a sourced comparison and dismiss an asserted one."],"focus":["precision","audience"]},
    {"id":"precision-fin-senior-21","level":"senior","profession":"finance","title":"The 'roughly' in the cash forecast","scenario":"Your 13-week cash forecast tells the exec team cash will be 'roughly fine' and the tight week is 'sometime in May.' A cash forecast that drives decisions can't traffic in 'roughly' — it needs the week and the buffer.","task":"Rewrite with the specific tight week and the exact minimum balance and buffer.","tips":["A cash forecast is the one place 'roughly' is unacceptable — give the week.","State the minimum balance and the buffer above the floor.","Precision here prevents a scramble later."],"focus":["precision","clarity"],"placeholder":"Cash troughs the week of May 12 at $8M — a $3M buffer over our $5M operating floor."},
    {"id":"precision-fin-senior-22","level":"senior","profession":"finance","title":"So-what for the pipeline coverage","scenario":"Your board slide shows pipeline coverage at 3.2x. Directors who don't live in the CRM don't know if that's good. The precision task is the so-what: 3.2x is below the 4x you need to hit the plan with normal close rates.","task":"Write the so-what sentence that turns 3.2x into a board-relevant judgment.","tips":["A ratio means nothing without its benchmark — state what's needed.","Say the implication: at 3.2x, hitting plan requires above-normal close rates.","Precision turns a metric into a risk the board can weigh."],"focus":["precision","impact"],"placeholder":"Pipeline coverage is 3.2x against the 4x we typically need — hitting plan now depends on close rates above trend."},
    {"id":"precision-fin-senior-23","level":"senior","profession":"finance","title":"The vague reason for the guidance beat","scenario":"You beat guidance and your draft credits 'strong execution and favorable conditions.' The board and investors want to know what specifically beat: which line, by how much, and whether it repeats.","task":"Rewrite crediting the specific driver, its size, and its repeatability.","tips":["'Strong execution' explains nothing — name the actual driver.","Quantify the beat by source and say if it's structural or one-time.","Repeatability is the question investors care about most — answer it."],"focus":["precision","audience"],"placeholder":"The beat came from two large renewals closing a quarter early — a $3M timing benefit that reverses next quarter."},
    {"id":"precision-fin-senior-24","level":"senior","profession":"finance","title":"The evidence for 'we're being prudent'","scenario":"You tell the board you're managing cash 'prudently.' A director pushes: prove it. Your draft restates the intention. Precision means showing the specific prudent actions and their measured effect.","task":"Replace 'prudent' with three specific actions and the cash each preserved.","tips":["'Prudent' is a virtue claim; the board wants the ledger.","List the actions: what you cut, deferred, or accelerated, with the dollars.","Measured prudence is credible; asserted prudence is not."],"focus":["precision","impact"]},
    {"id":"precision-fin-senior-25","level":"senior","profession":"finance","title":"The skeptic test on the ROI claim","scenario":"Your ERP business case claims a '3-year payback.' The board's skeptic will ask what's in the numerator and denominator, whether the benefits are cash or soft, and what happens if the project runs over. Your draft gives the payback with no support.","task":"Rewrite the payback claim to survive the skeptic: the cash benefits, the total cost, and the downside case.","tips":["A payback figure is only as good as the benefits behind it — itemize them.","Separate hard cash savings from soft 'productivity' benefits.","Show the payback if the project runs 20% over — the skeptic will."],"focus":["precision","impact"]}
  ],
  "executive-presence": [
    {"id":"presence-fin-senior-01","level":"senior","profession":"finance","title":"The capital menu that dodges the decision","scenario":"Your board memo lays out four capital-allocation options — buyback, dividend, debt paydown, reinvestment — with balanced pros and cons for each, and no recommendation. The board hired you to have a view, and the menu reads as ducking the call.","task":"Rewrite the closing so you own a single recommendation and rank the alternatives against it.","tips":["A balanced menu with no verdict is abdication, not analysis.","State your recommendation, then say why the runners-up lose.","The board can overrule you — but they need something to overrule."],"focus":["impact","structure"],"placeholder":"I recommend debt paydown this year; reinvestment is the close second, and here's why the buyback ranks below both."},
    {"id":"presence-fin-senior-02","level":"senior","profession":"finance","title":"Signposting the audit-committee update","scenario":"Your audit-committee update runs long and the committee loses the thread halfway through. You need to signpost: tell them the three things you'll cover, cover them, and mark the transitions so they always know where they are.","task":"Write the signposted opening (the three-part roadmap) and one transition line.","tips":["Announce the structure so listeners can track you.","'Three things: controls, the remediation, and one open item' orients the room.","Transitions ('that's controls — now remediation') keep everyone with you."],"focus":["structure","impact"]},
    {"id":"presence-fin-senior-03","level":"senior","profession":"finance","title":"Fact and judgment, tangled","scenario":"Your reforecast note braids fact and opinion: 'Revenue is down 3%, which is deeply concerning and probably means the plan was too aggressive.' The board can't tell where the data ends and your interpretation begins.","task":"Rewrite separating the facts from your judgment, labeling each.","tips":["State the facts cleanly, then your reading of them, distinctly.","'Revenue is down 3%' is fact; 'the plan was aggressive' is your judgment — mark it.","Directors weigh facts and opinions differently; don't blur them."],"focus":["precision","impact"],"placeholder":"Fact: revenue is 3% below plan. My read: the plan front-loaded too much of the year — I'd rebase the second half."},
    {"id":"presence-fin-senior-04","level":"senior","profession":"finance","title":"Owning the guidance call","scenario":"The exec team is split on whether to cut guidance. As CFO, you have a view — cut now, cleanly — but your draft to the CEO presents 'both sides for you to decide.' That's not presence; that's handing back the decision they expect you to shape.","task":"Write the recommendation that owns the call and gives the CEO a clear position to react to.","tips":["The CEO wants your recommendation, not a referee's summary.","State what you'd do and the one risk that would change your mind.","Presenting 'both sides' when you have a view reads as hedging your career."],"focus":["impact","clarity"],"placeholder":"My recommendation is to cut guidance now and cut it once —"},
    {"id":"presence-fin-senior-05","level":"senior","profession":"finance","title":"The recommendation that trails off","scenario":"You end your board presentation on the acquisition with 'so those are the considerations, and we're happy to go whichever way the board prefers.' A strong close states your recommendation and stands behind it.","task":"Rewrite the closing 2-3 sentences to end on a clear, owned recommendation.","tips":["Don't end on 'whichever way you prefer' — end on your view.","A CFO who won't recommend on a deal invites doubt about the deal.","State the recommendation, the price discipline, and the one condition."],"focus":["impact","clarity"]},
    {"id":"presence-fin-senior-06","level":"senior","profession":"finance","title":"Presence on a shaky number","scenario":"You're presenting a forecast you're genuinely uncertain about. Weak presence over-hedges until the number looks worthless; strong presence states the number, owns the uncertainty precisely, and still gives the board something to hold.","task":"Write the 2-3 sentence framing that presents the number with calibrated, owned uncertainty.","tips":["Own the number and the uncertainty in the same breath — both clearly.","State your best estimate, then the specific thing that could move it.","Confidence isn't pretending to be certain; it's being clear about what you know."],"focus":["impact","precision"],"placeholder":"My base case is $415M. The swing factor is the enterprise pipeline — if two deals slip, we're at $400M, and I'll know by mid-quarter."},
    {"id":"presence-fin-senior-07","level":"senior","profession":"finance","title":"The apologetic cost recommendation","scenario":"Your memo recommending the hiring freeze is laced with apology: 'I know this is unpopular, I hate to be the one to say it, I realize the timing is hard.' The recommendation is sound; the apologizing undermines your authority to make it.","task":"Rewrite owning the recommendation without the apology, acknowledging the cost once and moving on.","tips":["Apology signals you don't believe your own recommendation.","Acknowledge the human cost once, factually, then make the case.","Presence is standing behind a hard call, not softening it into mush."],"focus":["impact","clarity"]},
    {"id":"presence-fin-senior-08","level":"senior","profession":"finance","title":"Signposting the earnings remarks","scenario":"Your prepared earnings remarks flow as an undifferentiated stream. Analysts modeling in real time need signposts — 'now to margins,' 'turning to guidance' — so they can find and file each piece.","task":"Write the three signpost transitions for a results / drivers / outlook structure.","tips":["Signposts let analysts navigate and quote you accurately.","Name each section as you enter it — remove their guesswork.","Clean transitions read as command of the material."],"focus":["structure","audience"]},
    {"id":"presence-fin-senior-09","level":"senior","profession":"finance","title":"The financing recommendation with no spine","scenario":"You've analyzed three financing structures. Your memo describes each neutrally and says 'we look forward to the board's guidance.' The board's guidance is: tell us what you think. A CFO's presence is in the recommendation, not the survey.","task":"Write the opening that states your recommended structure and frames the analysis as support for it.","tips":["Lead with the structure you recommend and the reason in one line.","The three-option analysis becomes evidence for your pick.","'We look forward to your guidance' is what you say after you've recommended."],"focus":["impact","structure"],"placeholder":"I recommend the term loan over the bond and the revolver draw — it's the cheapest capital with the covenants we can live with."},
    {"id":"presence-fin-senior-10","level":"senior","profession":"finance","title":"The 'I feel' versus 'the data shows'","scenario":"In your risk memo, you write 'I feel like customer concentration is getting dangerous.' A director will trust 'the data shows concentration reached 18%, up from 12%' far more. Presence means grounding judgment in fact, then owning the judgment.","task":"Rewrite grounding the concern in data, then stating your judgment as judgment.","tips":["Lead with the fact that justifies the feeling.","Then own the judgment plainly: 'I consider this our top revenue risk.'","'I feel like' undersells a view the data actually supports."],"focus":["precision","impact"],"placeholder":"Concentration reached 18%, up from 12% a year ago. I consider this our single largest revenue risk and want a diversification target."},
    {"id":"presence-fin-senior-11","level":"senior","profession":"finance","title":"Taking the room on a contested call","scenario":"At the exec meeting, the COO wants to accelerate spend and you think it's premature. Weak presence lets the disagreement stay implicit; strong presence states your position clearly, names the disagreement, and proposes how to resolve it.","task":"Write the 2-3 sentences you'd say to make your position and the path to decision explicit.","tips":["Name the disagreement openly — it's already in the room.","State your position and the specific condition that would change it.","Propose the resolution: what evidence or trigger settles it."],"focus":["impact","clarity"]},
    {"id":"presence-fin-senior-12","level":"senior","profession":"finance","title":"The recommendation hidden in options","scenario":"Your board deck on the dividend policy presents 'Option A, Option B, Option C' with equal weight across six slides. A director asks, 'What do you recommend?' and you realize the deck never says. Presence is building the deck around your recommendation.","task":"Rewrite the deck's framing sentence so it leads with your recommendation and treats the options as the road not taken.","tips":["Build the deck around your answer, not around a fair contest.","Options B and C exist to show you considered them, not to share the stage.","A director should never have to ask what you recommend."],"focus":["impact","structure"],"placeholder":"We recommend initiating a modest dividend now; the alternatives — a larger dividend or none — trade off in ways I'll show, but this is the balance we'd strike."},
    {"id":"presence-fin-senior-13","level":"senior","profession":"finance","title":"The steady voice in a bad quarter","scenario":"You're delivering a miss to the board, and your instinct is either to catastrophize or to minimize. Presence is neither: state the miss plainly, own your read of why, and lead into the response without drama or denial.","task":"Write the 3-sentence framing that delivers the miss with steady, owned presence.","tips":["Neither panic nor spin — the board reads both as loss of control.","State the miss, your diagnosis, and your response, in that order.","Steadiness in a bad quarter is the presence directors remember."],"focus":["impact","clarity"]},
    {"id":"presence-fin-senior-14","level":"senior","profession":"finance","title":"Owning a number you inherited","scenario":"The forecast miss traces to an assumption your predecessor set, and it's tempting to say so. But you own the number now. Presence is taking accountability for the current state while being factual about the cause, without hiding behind history.","task":"Write the 2-3 sentences that own the miss without blaming your predecessor.","tips":["Own it: 'we,' not 'the previous team.'","You can state the root cause factually without assigning blame.","Blaming the past reads as weak; owning the present reads as strong."],"focus":["impact","clarity"]},
    {"id":"presence-fin-senior-15","level":"senior","profession":"finance","title":"The recommendation with a real caveat","scenario":"You recommend the acquisition, but there's a genuine risk — customer concentration at the target. Weak presence buries the risk; false confidence ignores it. Real presence recommends clearly and names the one risk that could change the answer.","task":"Write a recommendation that commits and states the single condition under which you'd reverse.","tips":["Commit to the recommendation first, unambiguously.","Name the one risk honestly and what would trigger a reversal.","A recommendation with a named caveat is stronger, not weaker."],"focus":["impact","precision"],"placeholder":"I recommend we proceed at up to 9x. The one thing that would stop me: if diligence shows their top customer is at renewal risk."},
    {"id":"presence-fin-senior-16","level":"senior","profession":"finance","title":"Presence when you're the most junior in the room","scenario":"You're the newest exec, presenting to a board that's been together for years. Weak presence defers reflexively; strong presence contributes your view with the same clarity as anyone else's, grounded in your analysis.","task":"Write the 2-3 sentences that state your view confidently to a room senior to you.","tips":["Your title is in the room; you don't need to earn the right to speak.","Ground the view in your analysis, then state it plainly.","Over-deference telegraphs that even you don't trust your work."],"focus":["impact","audience"]},
    {"id":"presence-fin-senior-17","level":"senior","profession":"finance","title":"The judgment call the board wants","scenario":"The board asks whether the company should self-insure a risk or keep buying coverage. There's real analysis on both sides, but they want your judgment. Weak presence recites the analysis; strong presence gives the call and the reasoning.","task":"Write the 2-3 sentence answer that leads with your judgment, then the reasoning.","tips":["Lead with the call: 'I'd keep the coverage this year.'","Then the reasoning, briefly — the analysis supports the judgment.","'It depends' is only presence if you then say on what, and decide."],"focus":["impact","clarity"]},
    {"id":"presence-fin-senior-18","level":"senior","profession":"finance","title":"Standing behind a number to investors","scenario":"On the call, an analyst challenges your margin guidance as too optimistic. Weak presence retreats; strong presence holds the number, acknowledges the analyst's point specifically, and explains why you're still confident.","task":"Write the 3-sentence response that holds your number while engaging the challenge honestly.","tips":["Don't retreat from a number you believe under one challenge.","Acknowledge the specific concern — it shows you're not defensive.","Then hold the line with the evidence that grounds your confidence."],"focus":["impact","audience"]},
    {"id":"presence-fin-senior-19","level":"senior","profession":"finance","title":"The all-hands close that whimpers","scenario":"Your all-hands finance segment ends: 'anyway, that's about it, happy to take any questions I guess.' After ten minutes of good content, the weak close undoes the presence. A strong close restates the one message and lands.","task":"Rewrite the closing 2 sentences to end with authority on the key message.","tips":["Don't trail off — end on the sentence you want them to carry out.","Restate the one message; that's what a strong close is for.","'That's about it, I guess' erases the presence you just built."],"focus":["impact","concision"]},
    {"id":"presence-fin-senior-20","level":"senior","profession":"finance","title":"Fact, judgment, and recommendation, cleanly staged","scenario":"Your cost-program memo mixes 'spend is up 12%' (fact), 'this is unsustainable' (judgment), and 'freeze discretionary now' (recommendation) in one run-on. Presence is staging them so the board sees the logic move from fact to call.","task":"Rewrite as three distinct, sequenced sentences: fact, judgment, recommendation.","tips":["Separate the three so the reasoning is inspectable.","Fact grounds judgment; judgment justifies the recommendation.","A board that sees the chain trusts the conclusion more."],"focus":["structure","impact"],"placeholder":"Fact: discretionary spend is 12% over plan. Judgment: at this trajectory we miss the margin target. Recommendation: freeze discretionary spend starting Monday."},
    {"id":"presence-fin-senior-21","level":"senior","profession":"finance","title":"Owning the call under a split board","scenario":"The board is visibly divided on the buyback. You have a view. Weak presence tries to please both camps and satisfies neither; strong presence states your recommendation and gives the divided room a clear position to converge on or reject.","task":"Write the 2-3 sentences that state your recommendation to a divided board without pandering.","tips":["A divided room needs a clear proposal, not a compromise mush.","State your recommendation and the principle behind it.","Trying to please both sides forfeits the presence to lead either."],"focus":["impact","audience"]},
    {"id":"presence-fin-senior-22","level":"senior","profession":"finance","title":"The confident 'here's what I'd do'","scenario":"The CEO asks, informally, what you'd do about the cash squeeze if it were your call alone. This is a presence moment: not a hedged menu, but a direct 'here's what I'd do and why,' delivered as someone who has decided.","task":"Write the 3-sentence answer: what you'd do, the sequence, and the reason.","tips":["The CEO asked what you'd do — answer that, decisively.","Give the sequence: first this, then that.","This is the moment to sound like someone who's already run it in their head."],"focus":["impact","clarity"],"placeholder":"If it were mine to call: I'd draw the revolver now for the buffer, then fix collections, and only cut spend if neither closes the gap."},
    {"id":"presence-fin-senior-23","level":"senior","profession":"finance","title":"Presence in writing the guidance sentence","scenario":"The single sentence that states next year's guidance will be quoted verbatim by every analyst. Weak presence over-qualifies it into vagueness; strong presence writes it to be precise, owned, and quotable.","task":"Write the guidance sentence with the presence to be quoted as-is.","tips":["This sentence will be repeated exactly — make it precise and clean.","Own the number; a hedged guidance sentence invites doubt.","One clear range, one honest condition, no ritual qualifiers."],"focus":["impact","precision"],"placeholder":"We expect full-year revenue of $440-460M and operating margin of 22-23%, assuming enterprise demand holds at current levels."},
    {"id":"presence-fin-senior-24","level":"senior","profession":"finance","title":"The recommendation the CFO must sign","scenario":"The provision for the tax exposure is a judgment call, and legal, tax, and audit each lean differently. As CFO you sign the number. Presence is making the call, stating the reasoning, and owning it — not deferring to the loudest advisor.","task":"Write the 2-3 sentences recording your decision on the provision and why.","tips":["Weigh the advice, then decide — the signature is yours.","State the number, the reasoning, and that you own the call.","Deferring to whoever spoke last is the opposite of presence."],"focus":["impact","clarity"]},
    {"id":"presence-fin-senior-25","level":"senior","profession":"finance","title":"The steering-committee call that needs a driver","scenario":"The ERP steering committee is stuck between delaying go-live and pushing through with known risks. Everyone's presenting considerations; nobody's driving. As the finance sponsor, presence is stating the recommendation and putting the decision on the table.","task":"Write the 2-3 sentences that name the decision, state your recommendation, and ask for the call.","tips":["A stuck committee needs someone to name the decision — do it.","State your recommendation and the reason it beats the alternative.","End by asking for the decision, not for more discussion."],"focus":["impact","structure"],"placeholder":"We need to decide today: I recommend we delay go-live to September rather than cut over on data we don't trust —"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-fin-senior-01","level":"senior","profession":"finance","title":"The analyst's yes-or-no on guidance","scenario":"On the earnings call, an analyst asks flatly: 'Are you still comfortable with the full-year guidance — yes or no?' Your instinct is to explain the puts and takes first. But the analyst asked a binary, and dodging it will be the headline.","task":"Write the answer that gives the yes or no first, then the one qualification.","tips":["Answer the binary in the first word — yes or no.","Then, and only then, the one caveat that matters.","Leading with the puts and takes reads as evasion on a live call."],"focus":["clarity","impact"],"placeholder":"Yes — we're holding full-year guidance, with the caveat that it now assumes the enterprise pipeline converts as planned."},
    {"id":"pressure-fin-senior-02","level":"senior","profession":"finance","title":"The director who challenges your forecast","scenario":"A director says in the meeting: 'Your forecasts have missed three quarters running — why should we believe this one?' It's pointed and it's fair. Defensiveness will make it worse; the answer is to engage the specific track record and what's changed.","task":"Write a 3-sentence response that owns the record and gives a concrete reason to trust the new number.","tips":["Acknowledge the record directly — don't minimize a fair hit.","Name what specifically was wrong in the misses and what you fixed.","Give the concrete change, not a promise to do better."],"focus":["impact","precision"]},
    {"id":"pressure-fin-senior-03","level":"senior","profession":"finance","title":"The 'I don't know' with a path","scenario":"In the audit-committee meeting, a member asks whether a specific vendor contract triggers a new accounting treatment. You genuinely don't know yet — it needs review. The wrong move is to bluff; the right move is an honest 'I don't know' plus a path.","task":"Write the 2-sentence answer that admits the gap and commits to a specific answer by a date.","tips":["'I don't know' is fine; 'I don't know and won't find out' is not.","Commit to who will check and by when.","A confident bluff that's wrong costs more than an honest gap."],"focus":["clarity","precision"],"placeholder":"I don't want to guess on that — it depends on the contract's specific terms. I'll have tax review it and come back to the committee by Friday."},
    {"id":"pressure-fin-senior-04","level":"senior","profession":"finance","title":"The CEO's pointed hallway question","scenario":"The CEO stops you: 'Are we going to make the quarter or not?' You want to walk them through the pipeline. But it's a hallway and a direct question. Answer it, then offer the detail.","task":"Write the 2-sentence answer: the direct call first, then the one thing it hinges on.","tips":["Give the CEO the answer they asked for, first.","Then the single swing factor, not the full pipeline tour.","In a hallway, brevity is respect for a direct question."],"focus":["clarity","concision"],"placeholder":"Right now, probably yes — but it hinges on the Meridian renewal closing this week."},
    {"id":"pressure-fin-senior-05","level":"senior","profession":"finance","title":"The loaded question with a false premise","scenario":"An analyst asks: 'Given that your margins are collapsing, how long can you sustain the dividend?' Margins aren't collapsing — they dipped 40 basis points on a deliberate investment. You have to correct the premise without sounding defensive, then answer.","task":"Write the 3-sentence answer that corrects the premise cleanly, then addresses the real question.","tips":["Correct the false premise first, calmly and with the number.","Don't let the loaded framing stand by answering as if it were true.","Then answer the legitimate underlying question about the dividend."],"focus":["clarity","precision"],"placeholder":"Margins didn't collapse — they dipped 40 basis points on a deliberate investment we've flagged. On the dividend:"},
    {"id":"pressure-fin-senior-06","level":"senior","profession":"finance","title":"The follow-up that keeps pushing","scenario":"You answered a director's question on covenant headroom, and they push again: 'But what if EBITDA drops 20% — then what?' They want the stress case, not reassurance. The pressure move is to give the specific stressed number, not to soothe.","task":"Write the answer that gives the actual stressed-case number and the action it would trigger.","tips":["When pushed for the downside, give the downside — specifically.","State the stressed ratio and whether it breaches.","Then the pre-planned action; that's what turns a scary number into a governed one."],"focus":["precision","impact"],"placeholder":"At a 20% EBITDA drop, leverage hits 3.8x — still inside the 4.0x covenant, and at that point we'd draw the amendment we've pre-negotiated."},
    {"id":"pressure-fin-senior-07","level":"senior","profession":"finance","title":"The question you can't fully answer in public","scenario":"On the earnings call, an analyst asks about a specific customer you can't name for confidentiality. You can't answer directly, but 'no comment' sounds evasive. The move is to answer what you can and be explicit about what you can't and why.","task":"Write the 2-3 sentence answer that gives what you can and names the boundary honestly.","tips":["Answer the part you can before flagging the part you can't.","Name the reason for the boundary — confidentiality, not evasion.","Offer the general pattern if you can't give the specific."],"focus":["clarity","audience"]},
    {"id":"pressure-fin-senior-08","level":"senior","profession":"finance","title":"The banker probing the weak spot","scenario":"In the financing negotiation, the lead banker zeroes in: 'Your interest coverage is thin — walk me through why we should be comfortable.' It's the real weak spot. Deflecting will cost you credibility; engaging it directly with the mitigants is the move.","task":"Write the 3-sentence answer that engages the weak spot honestly and gives the specific mitigants.","tips":["Don't deflect the banker's best question — they've seen the deflection before.","Acknowledge the coverage is tight, with the number.","Then the concrete mitigants: cash buffer, deleveraging path, flexibility."],"focus":["precision","impact"]},
    {"id":"pressure-fin-senior-09","level":"senior","profession":"finance","title":"The board member who wants a number you don't have live","scenario":"A director asks for the exact ARR churn rate mid-meeting and you don't have it memorized to the decimal. Fumbling for a guess erodes trust. The move is to give the range you're confident in and commit to the precise figure after.","task":"Write the 2-sentence answer that gives the confident range now and the precise number later.","tips":["Give the range you'd stake your name on, not a fabricated exact figure.","Commit to the precise number by end of day.","A confident range beats a wrong decimal every time."],"focus":["precision","clarity"],"placeholder":"It's in the low double digits — call it 11 to 13% — and I'll get you the exact figure by end of day."},
    {"id":"pressure-fin-senior-10","level":"senior","profession":"finance","title":"The accusatory question at the all-hands","scenario":"At the all-hands, an employee asks pointedly: 'You cut our travel budget but the exec team flew to an offsite — how is that fair?' It's confrontational and public. Getting defensive loses the room; answering the actual fairness question honestly keeps it.","task":"Write the 3-sentence answer that takes the fairness question seriously without defensiveness.","tips":["Answer the fairness question, not the surface facts.","Don't get defensive — the room is watching how you handle heat.","Be specific about what the offsite cost and why, or concede the point."],"focus":["audience","impact"]},
    {"id":"pressure-fin-senior-11","level":"senior","profession":"finance","title":"The CEO reframes to avoid your answer","scenario":"You told the CEO the acquisition model doesn't support the price. They reframe: 'But strategically, isn't this a must-do?' They're moving the question to dodge your finance answer. The pressure move is to answer the strategic frame without abandoning the number.","task":"Write the 2-3 sentence response that engages the strategic question while holding the financial discipline.","tips":["Engage the reframe — don't just repeat your original number.","Concede the strategic logic where it's real.","Then re-anchor: strategy justifies a price, but not any price — here's the ceiling."],"focus":["impact","clarity"],"placeholder":"Strategically, yes, it's compelling — which is why I'd pay a premium. But the model says the premium tops out at 9x, and above that we're destroying value even on the strategic case."},
    {"id":"pressure-fin-senior-12","level":"senior","profession":"finance","title":"The rapid-fire on the earnings call","scenario":"An analyst stacks three questions in one breath: margins, capex, and the buyback timeline. Under pressure, people answer the easiest and drop the rest. The move is to acknowledge all three, answer crisply, and not let one get buried.","task":"Write the opening that flags all three and answers the first crisply.","tips":["Name the three so the analyst knows you caught them all.","Answer in order; don't cherry-pick the comfortable one.","Crisp on each beats thorough on one and silent on two."],"focus":["structure","clarity"]},
    {"id":"pressure-fin-senior-13","level":"senior","profession":"finance","title":"The hostile 'you don't understand the business'","scenario":"A business-unit head, angry about a budget cut, says in the review: 'Finance just doesn't understand what it takes to run this unit.' It's a shot at your credibility in front of peers. Escalating loses; engaging the substance with specifics wins.","task":"Write the 3-sentence response that doesn't take the bait and redirects to the actual constraint.","tips":["Don't defend your understanding — demonstrate it with a specific.","Acknowledge the unit's reality, then state the shared constraint.","Redirect from 'who understands what' to 'here's the number we both live with.'"],"focus":["audience","impact"]},
    {"id":"pressure-fin-senior-14","level":"senior","profession":"finance","title":"The question that exposes a real mistake","scenario":"A director asks why the prior forecast was so far off, and the honest answer is you missed a churn signal that was visible in the data. The pressure is to obscure it; the presence move is to own the specific miss and what you changed.","task":"Write the 2-3 sentence answer that owns the specific error and the fix, without groveling.","tips":["Own the specific mistake — vagueness reads as hiding.","State what you changed so it doesn't recur.","One clean acknowledgment; don't over-apologize into weakness."],"focus":["clarity","impact"]},
    {"id":"pressure-fin-senior-15","level":"senior","profession":"finance","title":"The 'just give me a number' pressure","scenario":"The CEO wants a single revenue number for the board and you keep giving a range. They press: 'I need one number.' The honest move isn't to cave to false precision — it's to give the number you'd commit to and be clear it's a commitment, not a certainty.","task":"Write the 2-sentence answer that gives the single committable number and frames what it is.","tips":["Give the number, but frame it as your commit point, not a guarantee.","Committing to a number is different from pretending to certainty.","State the number you'd defend, and note the risk direction."],"focus":["precision","impact"],"placeholder":"If you need one number, it's $415M — that's my commit point, and the risk is to the downside if two enterprise deals slip."},
    {"id":"pressure-fin-senior-16","level":"senior","profession":"finance","title":"The trap question in the diligence call","scenario":"On the sell-side diligence call, the buyer's advisor asks: 'Is there anything about the revenue quality you haven't disclosed?' It's a fishing question aimed at your integrity. You answer honestly, but you don't volunteer beyond the question or sound evasive.","task":"Write the 2-3 sentence answer that's honest, complete to the question, and not defensive.","tips":["Answer honestly and completely — integrity questions have long memories.","Point to what's already disclosed rather than sounding like you're hiding.","Don't over-volunteer, but don't hedge in a way that invites suspicion."],"focus":["clarity","precision"]},
    {"id":"pressure-fin-senior-17","level":"senior","profession":"finance","title":"The board wants certainty you can't give","scenario":"The board asks: 'Guarantee us cash won't be an issue this year.' You can't guarantee that honestly. The pressure move isn't false reassurance — it's giving them the real confidence level and the specific safeguards that back it.","task":"Write the 3-sentence answer that refuses the false guarantee while giving genuine assurance.","tips":["Don't give a guarantee you can't honor — the board will remember.","State the real confidence: base case is safe, here's the buffer.","Name the specific safeguard that handles the downside."],"focus":["clarity","precision"]},
    {"id":"pressure-fin-senior-18","level":"senior","profession":"finance","title":"The interruption before you finish the answer","scenario":"You're two sentences into answering a director's question when another director jumps in with a different concern. You can lose your thread and answer neither well. The move is to briefly hold your line, finish the first answer, then take the second.","task":"Write the one-line bridge that finishes your point and acknowledges the new question.","tips":["Politely finish the answer in progress — one clean sentence.","Then explicitly turn to the new question so neither is dropped.","Losing your thread under interruption reads as losing control."],"focus":["structure","clarity"]},
    {"id":"pressure-fin-senior-19","level":"senior","profession":"finance","title":"The analyst who won't accept the answer","scenario":"You've answered the analyst's margin question twice, and they ask it a third way, implying they don't believe you. The move under this pressure isn't to repeat louder — it's to offer the specific proof point that resolves the doubt.","task":"Write the 2-3 sentence response that offers concrete evidence rather than restating the claim.","tips":["Repeating the same answer louder doesn't build belief.","Offer a new, specific proof point they can verify.","Name what would confirm your claim next quarter — a falsifiable marker."],"focus":["precision","impact"]},
    {"id":"pressure-fin-senior-20","level":"senior","profession":"finance","title":"The whole-company question you can't fully answer","scenario":"At the all-hands, someone asks whether there will be layoffs. You don't have a final answer — no decision has been made — but 'no comment' will terrify the room and a false 'no' would be a betrayal. The move is honest, careful, and specific about what you can say.","task":"Write the 3-sentence answer that's truthful, humane, and clear about what's decided and what isn't.","tips":["Don't promise what you can't; don't stonewall a scared room.","Say clearly what's decided (nothing) and what would change that.","Commit to how and when people would hear — honesty about process reassures."],"focus":["audience","clarity"]},
    {"id":"pressure-fin-senior-21","level":"senior","profession":"finance","title":"The rating-agency analyst tests your assumptions","scenario":"The rating-agency analyst says: 'Your deleveraging plan assumes EBITDA grows 10% — that seems aggressive given the sector.' They're testing whether your base case is credible. The move is to defend the assumption with specifics or concede and show the plan still works without it.","task":"Write the 3-sentence answer that defends the assumption with evidence or shows resilience without it.","tips":["Defend the assumption with the specific drivers, if it's defensible.","If it's aggressive, show the plan still deleverages at a lower growth rate.","Agencies reward a plan that survives its own assumptions being wrong."],"focus":["precision","impact"]},
    {"id":"pressure-fin-senior-22","level":"senior","profession":"finance","title":"The CEO puts you on the spot in front of the board","scenario":"Mid-meeting the CEO turns to you: 'Tell the board why you're confident in the number.' You weren't planning to speak yet. The move is to give a crisp, structured answer on the spot, not to ramble while you find your footing.","task":"Write the 3-sentence on-the-spot answer: the confidence, the two reasons, done.","tips":["State the confidence level first, cleanly.","Two reasons, not five — you're improvising, keep it tight.","A structured 20-second answer beats a searching two-minute one."],"focus":["structure","impact"]},
    {"id":"pressure-fin-senior-23","level":"senior","profession":"finance","title":"The question designed to make you contradict yourself","scenario":"An analyst notes: 'Last quarter you said margins would expand; this quarter they contracted. Which is it?' They're hunting for a contradiction. The move is to reconcile the two honestly — the deliberate investment — not to pretend you never said it.","task":"Write the 3-sentence answer that reconciles the apparent contradiction with the actual reason.","tips":["Don't deny what you said — reconcile it.","Explain the deliberate choice that connects the two statements.","Owning the sequence honestly defuses the 'gotcha.'"],"focus":["clarity","precision"]},
    {"id":"pressure-fin-senior-24","level":"senior","profession":"finance","title":"The hostile takeover question at the AGM","scenario":"At the shareholder meeting, an activist asks: 'Why should shareholders trust management's capital allocation when the stock has underperformed?' It's adversarial and public. The move is to answer the substance with specifics, not to get defensive or dismissive.","task":"Write the 3-sentence answer that engages the challenge with concrete capital-allocation evidence.","tips":["Take the challenge seriously — dismissiveness plays badly in public.","Point to specific capital decisions and their measurable returns.","Acknowledge the stock concern without conceding the whole premise."],"focus":["audience","impact"]},
    {"id":"pressure-fin-senior-25","level":"senior","profession":"finance","title":"The question after the bad news lands","scenario":"You've just told the board you're cutting guidance. The first question is sharp: 'How did you not see this coming?' Under the pressure of having delivered bad news, the temptation is to defend. The move is to answer the actual question — what you missed and what's now different.","task":"Write the 3-sentence answer that honestly addresses the foresight question without defensiveness.","tips":["Answer the real question: what signal did you miss, and when.","Own it plainly; the bad news already landed, don't compound it with spin.","Pivot to what's now in place so it's caught earlier next time."],"focus":["clarity","impact"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-fin-senior-01","level":"senior","profession":"finance","title":"The before-and-after for the ERP investment","scenario":"You're asking the board for $6M for a new ERP. A list of features won't persuade them. What persuades is the contrast: the painful present (five-day closes, manual reconciliation, error risk) versus the credible after (two-day closes, real-time visibility).","task":"Write the before/after framing in 3-4 sentences that make the change vivid and worth $6M.","tips":["Paint the current pain concretely — the board should feel the friction.","Then the after-state, specific enough to be believable.","The gap between them is the argument for the spend."],"focus":["impact","structure"],"placeholder":"Today, closing the books takes five days of manual reconciliation, and every close carries error risk. With the new system, we close in two —"},
    {"id":"narrative-fin-senior-02","level":"senior","profession":"finance","title":"Making the abstract cost real","scenario":"You want the exec team to take the working-capital problem seriously, but 'DSO increased 7 days' is abstract. Persuasion means making the stakes concrete: those 7 days are $6M of cash locked up — enough to fund the two hires each of them is fighting for.","task":"Write the 2-3 sentence framing that converts the abstract metric into a stake the room feels.","tips":["Translate the metric into something the audience wants or fears losing.","'$6M locked up' means nothing until it's 'the headcount you're all asking for.'","Concrete stakes move people; abstract ones get nodded at and ignored."],"focus":["impact","audience"],"placeholder":"Those seven extra days of DSO are $6M of cash sitting in receivables — enough to fund every open req in this room."},
    {"id":"narrative-fin-senior-03","level":"senior","profession":"finance","title":"Pre-empting the objection to the buyback","scenario":"You're recommending a buyback to the board, and you know the strongest objection: 'shouldn't we save the cash for the downturn everyone's predicting?' Persuasion means raising and answering that objection before a director does, so your case looks complete.","task":"Write the 2-3 sentences that name the strongest objection and answer it before it's raised.","tips":["Name the objection yourself — it disarms the skeptic and builds trust.","Answer it with the specific safeguard: buffer retained, capacity preserved.","A case that pre-empts its best counter looks thought-through, not sold."],"focus":["impact","structure"],"placeholder":"The fair objection is: why not hoard cash for a downturn? Because even after this buyback we keep a 12-month buffer and full revolver capacity —"},
    {"id":"narrative-fin-senior-04","level":"senior","profession":"finance","title":"The investor story arc for a flat year","scenario":"Revenue is flat this year and you need investors to see it as a deliberate investment year, not stagnation. That's a narrative task: frame the flat number as the trough of an intentional arc, with the payoff visible ahead.","task":"Write the 3-4 sentence narrative that reframes a flat year as a deliberate, credible investment arc.","tips":["Give the flat number a story: what you chose to invest in and why now.","Make the payoff concrete and time-bound, not a vague 'future growth.'","The arc — deliberate dip, visible return — beats a defensive explanation."],"focus":["impact","audience"]},
    {"id":"narrative-fin-senior-05","level":"senior","profession":"finance","title":"Selling the cost program without fear","scenario":"You're announcing a cost program to the whole company. Framed as 'we're in trouble,' it spreads fear and people leave. Framed as 'we're choosing discipline to fund growth,' it can rally them. Same actions, different narrative, very different result.","task":"Write the 3-4 sentence framing that motivates the company toward the program rather than frightening it.","tips":["Frame the program as a choice for strength, not a reaction to weakness.","Connect the discipline to something people want — investment, stability, growth.","Be honest about the why without making it sound like survival mode."],"focus":["audience","impact"]},
    {"id":"narrative-fin-senior-06","level":"senior","profession":"finance","title":"The acquisition case as a story","scenario":"Your investment-committee pitch for the acquisition is all numbers and no narrative. The committee remembers stories. Frame it: here's the gap in our business, here's how this target fills it, here's what we become — with the numbers proving each beat.","task":"Write the 3-4 sentence narrative spine of the acquisition case, numbers supporting the story.","tips":["Structure as a story: the gap, the fit, the transformation.","Let each narrative beat be backed by one number, not buried in them.","A committee remembers 'this makes us the leader in X'; they forget the IRR."],"focus":["structure","impact"]},
    {"id":"narrative-fin-senior-07","level":"senior","profession":"finance","title":"The stakes in the covenant conversation","scenario":"You need the CEO to take the covenant risk seriously, but they see it as a technicality. Persuasion means making the stake vivid: a breach isn't a footnote — it's the bank able to demand repayment, freeze the revolver, and control the company's cash.","task":"Write the 2-3 sentences that make the real consequence of a breach concrete for the CEO.","tips":["A 'technical breach' sounds harmless — show what it actually unlocks.","Name the specific power it hands the lender.","Concrete consequence beats abstract ratio every time."],"focus":["impact","clarity"],"placeholder":"A breach isn't a technicality — it lets the bank demand repayment on 30 days' notice and freeze the revolver we rely on for payroll timing."},
    {"id":"narrative-fin-senior-08","level":"senior","profession":"finance","title":"Persuading the CEO to lower guidance","scenario":"The CEO resists cutting guidance because it 'looks like weakness.' Your persuasion isn't more data — it's reframing: cutting once and cleanly is strength; missing a number you defended is the real weakness investors punish.","task":"Write the 2-3 sentence reframe that makes cutting look like the strong move, not the weak one.","tips":["Reframe the choice: the weakness isn't the cut, it's the miss.","Invoke what investors actually punish — surprises, not resets.","Give the CEO a version of 'strong' they can act on."],"focus":["impact","audience"],"placeholder":"Cutting now, once, is the strong move — what investors punish isn't a reset, it's defending a number and then missing it."},
    {"id":"narrative-fin-senior-09","level":"senior","profession":"finance","title":"The before/after for centralizing finance","scenario":"You want to centralize the finance function, and the business units resist losing their embedded analysts. Persuasion is the contrast: today, inconsistent numbers and slow answers; after, one source of truth and faster decisions — with the units gaining, not losing.","task":"Write the 3-4 sentence before/after that shows the units what they gain, not just what changes.","tips":["Show the current pain the units actually feel, not the pain you feel.","Frame the after-state as a gain for them: faster, cleaner, more credible.","People resist loss; persuade by making the change a gain for the resister."],"focus":["audience","impact"]},
    {"id":"narrative-fin-senior-10","level":"senior","profession":"finance","title":"Pre-empting the dilution objection","scenario":"You're recommending an equity raise to fund growth, and the board's strongest objection is dilution. A persuasive memo names dilution head-on and shows why the growth it funds more than offsets it — before a director raises it as a dealbreaker.","task":"Write the 2-3 sentences that surface the dilution concern and answer it with the offsetting case.","tips":["Raise dilution before they do — ignoring it looks like you missed it.","Show the math: the growth the capital funds outweighs the dilution.","Frame it as per-share value created, which is what dilution really tests."],"focus":["impact","precision"]},
    {"id":"narrative-fin-senior-11","level":"senior","profession":"finance","title":"The human stake in the collections push","scenario":"You need sales and CS to prioritize collections, and 'improve DSO' won't move them. Persuasion means the human stake: every week of delay is cash that could fund the product roadmap they keep asking for, or the headcount they're short.","task":"Write the 2-3 sentence framing that ties collections to something sales and CS personally want.","tips":["Connect the ask to what this specific audience wants.","'DSO' is your metric; 'the roadmap you're waiting on' is their stake.","Make the cash tangible as the thing they'd get if it freed up."],"focus":["audience","impact"]},
    {"id":"narrative-fin-senior-12","level":"senior","profession":"finance","title":"The turnaround narrative for the bank","scenario":"You're asking the bank to extend the facility after a rough year. A defensive 'it wasn't our fault' won't persuade. The narrative that works: here's what went wrong, here's specifically what we changed, here's the early evidence it's working.","task":"Write the 3-4 sentence turnaround narrative that earns the bank's confidence to re-lend.","tips":["Own what went wrong — banks distrust borrowers who blame externally.","Show the specific changes, not intentions.","Lead the last beat with early proof the changes are landing."],"focus":["structure","impact"]},
    {"id":"narrative-fin-senior-13","level":"senior","profession":"finance","title":"Making the opportunity cost visible","scenario":"The board is comfortable holding excess cash, and you want to deploy it. The persuasive move is to make the invisible cost visible: cash earning 4% while your cost of capital is 11% is quietly destroying value every quarter it sits there.","task":"Write the 2-3 sentences that make the cost of idle cash vivid and urgent.","tips":["Idle cash feels safe; show that safety has a price.","Quantify the gap: earning 4% against an 11% cost of capital.","Make inaction feel like a decision with a cost, because it is."],"focus":["impact","precision"],"placeholder":"The $40M we're holding earns 4% while our cost of capital is 11% — that gap quietly costs us roughly $3M a year in foregone value."},
    {"id":"narrative-fin-senior-14","level":"senior","profession":"finance","title":"The 'why now' for the refinancing","scenario":"You want to refinance now, but the CFO's instinct in the room is 'the current facility is fine, why rock the boat?' Persuasion is the 'why now': rates are favorable, the window is closing, and waiting means refinancing later at a worse cost.","task":"Write the 2-3 sentence 'why now' that makes waiting feel like the risky choice.","tips":["Make the case for urgency, not just merit — why this window.","Frame delay as the risk: rates could rise, the window could close.","'The current facility is fine' is the objection — answer the 'why change.'"],"focus":["impact","structure"]},
    {"id":"narrative-fin-senior-15","level":"senior","profession":"finance","title":"The investor day narrative arc","scenario":"You have twenty minutes at the investor day and a pile of metrics. Investors won't remember the metrics; they'll remember the story. Build one: where the company was, the strategic shift you made, and the financial trajectory it's now on.","task":"Write the 3-4 sentence narrative arc that gives the metrics a story to hang on.","tips":["Give investors a three-act arc, not a metrics dump.","Anchor each act with the one number that proves it.","The story is what they repeat to their PM; the metrics are footnotes."],"focus":["structure","impact"]},
    {"id":"narrative-fin-senior-16","level":"senior","profession":"finance","title":"Pre-empting 'this is just cost-cutting'","scenario":"Your efficiency program will be read by employees as pure cost-cutting, which kills morale. The persuasive frame raises that reading directly and reframes: this is about redirecting spend from low-value to high-value work, not shrinking.","task":"Write the 2-3 sentences that name the 'it's just cuts' reading and reframe it credibly.","tips":["Say the cynical reading out loud — pretending it isn't there fails.","Reframe with specifics: what you're cutting versus what you're funding.","Credibility requires naming what grows, not just what shrinks."],"focus":["audience","impact"]},
    {"id":"narrative-fin-senior-17","level":"senior","profession":"finance","title":"The stakes of the systems risk","scenario":"You need investment in financial-systems resilience, but 'controls modernization' sounds like plumbing nobody funds. Persuasion means the stake: one material control failure could mean a restatement, a stock drop, and a governance crisis.","task":"Write the 2-3 sentences that make the downside of the systems risk concrete and board-relevant.","tips":["'Controls' is invisible until you show what failure costs.","Name the chain: control failure to restatement to market reaction.","Make the low-probability, high-severity risk feel worth insuring against."],"focus":["impact","precision"]},
    {"id":"narrative-fin-senior-18","level":"senior","profession":"finance","title":"The before/after for the pricing change","scenario":"You're recommending a pricing model change to the board, and a slide of margin math won't carry it. The narrative: today's model leaves money on the table and confuses customers; the new model captures value and simplifies the buy. Numbers prove it; story sells it.","task":"Write the 3-4 sentence before/after narrative for the pricing change.","tips":["Contrast the current model's specific failures with the new model's gains.","Include the customer's experience, not just the margin — it's more persuasive.","Let the numbers land inside the story, not as a separate slide."],"focus":["impact","structure"]},
    {"id":"narrative-fin-senior-19","level":"senior","profession":"finance","title":"Persuading the CEO to hold the line on price","scenario":"Sales is pushing discounts and the CEO is wavering. You need to persuade them to hold pricing. The narrative: every point of discount is pure margin gone, and once you train the market to expect discounts, you can't untrain it.","task":"Write the 2-3 sentences that make the long-term cost of discounting vivid to the CEO.","tips":["Show the immediate cost — discount is 100% margin — and the lasting one.","Frame the durable risk: discounting resets customer expectations permanently.","Give the CEO the argument to take back to sales."],"focus":["impact","clarity"],"placeholder":"Every point of discount is a point of pure margin gone — and once we discount to close, the market expects it next time, and we can't take it back."},
    {"id":"narrative-fin-senior-20","level":"senior","profession":"finance","title":"The reinvestment story for skeptical investors","scenario":"Investors want cash returned; you want to reinvest it. The persuasive narrative isn't 'trust us' — it's showing the specific returns available from reinvestment that beat what shareholders could earn with the cash themselves.","task":"Write the 3-4 sentence narrative that makes reinvestment the obviously better choice for the shareholder.","tips":["Frame it from the shareholder's return, not the company's ambition.","Show the reinvestment return beats their alternative use of the cash.","Concede where returning cash would be right — it makes the reinvest case credible."],"focus":["audience","impact"]},
    {"id":"narrative-fin-senior-21","level":"senior","profession":"finance","title":"Pre-empting the 'too optimistic' charge on the plan","scenario":"You're presenting next year's plan and you know the board will think it's too optimistic after a soft year. The persuasive move is to build the credibility in: show the plan is grounded in already-contracted revenue and conservative assumptions, before the skepticism forms.","task":"Write the 2-3 sentences that pre-empt the 'too optimistic' reaction with grounding evidence.","tips":["Anticipate the skepticism and defuse it up front.","Ground the plan in what's already booked, not what you hope to win.","Name your conservative choices so the plan reads as sandbagged, not stretched."],"focus":["impact","precision"]},
    {"id":"narrative-fin-senior-22","level":"senior","profession":"finance","title":"The stakes for the whole-company at the all-hands","scenario":"You're explaining to the whole company why hitting the cash target this quarter matters. 'Cash flow' is abstract to most of them. The persuasive frame: hitting it funds next year's raises and the product bets people care about; missing it forces choices nobody wants.","task":"Write the 3-4 sentence framing that makes the cash target matter to every employee.","tips":["Connect the target to outcomes employees personally care about.","Make both sides concrete: what hitting it enables, what missing it forces.","Avoid finance abstraction — speak in raises, roadmap, stability."],"focus":["audience","impact"]},
    {"id":"narrative-fin-senior-23","level":"senior","profession":"finance","title":"The persuasive close on the capital-allocation memo","scenario":"Your capital-allocation memo is analytically strong but ends flat. A persuasive close ties it together: this allocation isn't just optimal on the numbers — it's the disciplined path that compounds shareholder value over years, and here's what it makes possible.","task":"Write the 2-3 sentence persuasive close that elevates the recommendation beyond the math.","tips":["A strong close connects the decision to a larger trajectory.","Move from 'this is optimal' to 'this is who we're choosing to be.'","End on what the choice makes possible, not on a summary of the analysis."],"focus":["impact","structure"]},
    {"id":"narrative-fin-senior-24","level":"senior","profession":"finance","title":"Reframing the miss as a course correction","scenario":"You missed the quarter and have to present it to investors. A defensive narrative ('demand was soft') invites more skepticism. A persuasive one owns the miss, names the specific correction underway, and frames the reset as the foundation for credible future beats.","task":"Write the 3-4 sentence narrative that turns a miss into a credible course-correction story.","tips":["Own the miss cleanly — investors forgive honesty faster than spin.","Name the specific correction, not a general 'we're addressing it.'","Frame the reset base as the thing that makes future numbers trustworthy."],"focus":["impact","audience"]},
    {"id":"narrative-fin-senior-25","level":"senior","profession":"finance","title":"The full persuasive case for the financing structure","scenario":"You're recommending a specific financing structure to the board over two alternatives. You need a complete persuasive case: the situation that requires financing, why this structure fits, the strongest objection answered, and what it makes possible.","task":"Write the 4-sentence persuasive case: situation, recommendation, pre-empted objection, and payoff.","tips":["Open with the need, so the recommendation answers a real question.","State the structure and its core advantage in one line.","Name and answer the strongest objection, then close on what it enables."],"focus":["structure","impact"],"placeholder":"We need $50M to fund the integration without straining cash. I recommend the term loan: cheapest capital with covenants we can meet. The fair worry is the added leverage — but it deleverages below 2.5x within two years, and it lets us integrate without touching the revolver we need for operations."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-fin-senior-01","level":"senior","profession":"finance","title":"Telling the board the guidance was wrong","scenario":"You gave the board full-year guidance last quarter and now it's clearly unreachable. You have to tell them plainly. The temptation is to bury the reset in a wall of context; clear is kind — front-load the message, then explain.","task":"Write the opening 2-3 sentences that state the guidance miss before any context.","tips":["Lead with the hard message: guidance was too high and must come down.","Don't make the board dig for the point through paragraphs of setup.","Context after the message reads as explanation; before it, as evasion."],"focus":["clarity","impact"],"placeholder":"I need to tell you plainly: the full-year guidance I gave last quarter is no longer reachable, and we should lower it now."},
    {"id":"hard-fin-senior-02","level":"senior","profession":"finance","title":"The clean no to the CEO's pet project","scenario":"The CEO wants to fund their pet initiative, and the numbers don't support it. You have to say no. A soft, hedged no ('it's tricky, maybe we could revisit') wastes their time and yours. A clean no with the reason respects both.","task":"Write the clean 2-3 sentence no, with the reason and any real alternative.","tips":["Say no clearly — a mushy no is heard as maybe and revisited endlessly.","Give the specific reason, not a vague 'timing.'","If there's a real path or alternative, offer it; if not, don't invent one."],"focus":["clarity","impact"],"placeholder":"I can't fund this at the level you're asking — the return doesn't clear our hurdle, and funding it means cutting something with a stronger case."},
    {"id":"hard-fin-senior-03","level":"senior","profession":"finance","title":"Behavior, impact, ask for the controller","scenario":"Your controller has been late on the close three months running, and it's affecting the whole reporting cycle. You need to give feedback that lands. The structure that works: name the specific behavior, its impact, then ask — not vague disappointment.","task":"Write the 3-sentence feedback using behavior, impact, and a clear ask.","tips":["Name the specific behavior, not a character trait: 'the close slipped 3 days,' not 'you're unreliable.'","State the concrete impact on the cycle and the team.","End with a specific ask and offer to remove blockers."],"focus":["clarity","impact"],"placeholder":"The last three closes each ran three days late. That pushes the whole board-reporting cycle and forces the team into weekends. I need the close back on the two-day timeline — what's in the way?"},
    {"id":"hard-fin-senior-04","level":"senior","profession":"finance","title":"Telling a business unit their budget is cut","scenario":"A business unit's budget is being cut 15% and the head will be angry. Softening it into ambiguity ('we're rightsizing investments across the portfolio') is unkind — they'll misread the number. Clear is kind: state the cut, the number, the reason.","task":"Write the 2-3 sentences that deliver the specific cut plainly and respectfully.","tips":["State the actual number — vagueness now means a worse conversation later.","Give the real reason, even if it's hard to hear.","Respect isn't softening the message; it's being straight and available to discuss."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-05","level":"senior","profession":"finance","title":"The layoff communication to the company","scenario":"The company is reducing headcount by 8% and you're delivering the financial context in the all-hands. Euphemism ('optimizing our cost structure') insults people losing jobs. Clear is kind: name what's happening, why, and what's true about the path forward.","task":"Write the 3-4 sentence financial framing that's honest and humane, no euphemism.","tips":["Name it plainly — 'layoffs,' not 'rightsizing' — people deserve the truth.","Give the honest financial why without hiding behind jargon.","Be truthful about the forward path; false optimism erodes trust further."],"focus":["clarity","audience"]},
    {"id":"hard-fin-senior-06","level":"senior","profession":"finance","title":"Declining the acquisition the CEO wants","scenario":"The CEO is excited about an acquisition and you've concluded it doesn't work at any reasonable price. You have to deliver that. Hedging ('there are some concerns we'd want to work through') keeps false hope alive. A clear no with the reasoning is the honest move.","task":"Write the 2-3 sentences that clearly decline the deal with the core reason.","tips":["Be clear it's a no, not a 'needs more work' — don't string them along.","Give the fundamental reason the deal fails, not a list of quibbles.","Acknowledge the strategic appeal, then hold the line on value."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-07","level":"senior","profession":"finance","title":"The material weakness disclosure","scenario":"You have to tell the audit committee about a material weakness in controls. It's the kind of news people bury in qualifications. Clear is kind: state the weakness, its severity, and the remediation plan, without minimizing or catastrophizing.","task":"Write the 3-sentence disclosure: what the weakness is, its impact, and the plan.","tips":["State the weakness plainly — the committee needs the unvarnished version.","Be precise about impact: what it does and doesn't affect.","Pair the hard news with a concrete remediation plan and timeline."],"focus":["clarity","precision"],"placeholder":"We identified a material weakness in our revenue-recognition controls. No misstatement resulted, but the control gap could have allowed one. Here's the remediation plan and timeline:"},
    {"id":"hard-fin-senior-08","level":"senior","profession":"finance","title":"Saying no to the board's buyback request","scenario":"A board faction wants a buyback and you think it's the wrong use of cash right now. Deferring ('we could explore it') isn't leadership. The hard message: not now, here's why, and here's the condition under which you'd revisit.","task":"Write the 2-3 sentence no to the buyback, with the reason and the revisit condition.","tips":["Give a clear 'not now,' not an ambiguous 'let's study it.'","State the reason: better uses of cash, or preserving flexibility.","Name what would change your view — it shows you're reasoning, not blocking."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-09","level":"senior","profession":"finance","title":"Telling the CEO a favored vendor must go","scenario":"A vendor the CEO personally championed is underperforming and overpriced, and you're recommending you drop them. The relationship makes this awkward. Clear is kind: deliver the recommendation and the evidence directly, without dancing around the CEO's attachment.","task":"Write the 2-3 sentences that recommend dropping the vendor plainly, evidence first.","tips":["Lead with the recommendation and the hard number that drives it.","Acknowledge the relationship once, then let the evidence carry it.","Don't soften the data to protect feelings — that's the unkind option."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-10","level":"senior","profession":"finance","title":"The bonus-pool bad news to the team","scenario":"The bonus pool is coming in below target because the company missed plan, and you have to tell your finance team, who worked hard. Vague reassurance ('we're working on it') is worse than the truth. Clear is kind: the number, the reason, and what it means for them.","task":"Write the 3-sentence message that delivers the bonus news honestly to your team.","tips":["Give the honest number or range — ambiguity breeds worse rumors.","Explain the company reason without making the team feel it's their fault.","Say what's decided and what's still open, plainly."],"focus":["clarity","audience"]},
    {"id":"hard-fin-senior-11","level":"senior","profession":"finance","title":"Correcting a peer's number in the meeting","scenario":"In the exec meeting, the COO cites a revenue figure that's wrong and is building a plan on it. You have to correct it in the room without embarrassing them. Clear but kind: state the right number and its source, matter-of-factly, then move on.","task":"Write the 2-sentence correction that fixes the number without undermining the COO.","tips":["Correct the fact, not the person — keep it neutral and sourced.","State the right number plainly; don't dwell or score points.","Give them an easy out: 'the latest figure' rather than 'you're wrong.'"],"focus":["clarity","audience"],"placeholder":"Quick correction on that — the latest figure is $38M, not $42M; the $42M was pre-adjustment. The plan still works, just tighter."},
    {"id":"hard-fin-senior-12","level":"senior","profession":"finance","title":"The dividend cut to shareholders","scenario":"You have to announce a dividend cut, which retail shareholders will take hard. Burying it in the release or euphemizing ('recalibrating our capital return') betrays them. Clear is kind: state the cut, the reason, and what it protects.","task":"Write the 2-3 sentence shareholder communication that delivers the cut honestly.","tips":["State the cut and the new level plainly — no euphemism survives scrutiny.","Give the honest reason: what the retained cash protects or funds.","Respect the shareholder by being straight, not by spinning."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-13","level":"senior","profession":"finance","title":"Telling the CEO you disagree with the strategy","scenario":"You believe the CEO's growth-at-all-costs strategy is heading toward a cash crisis, and you have to say so. Silence is complicity; a clear, respectful disagreement is your job. Deliver the concern directly, grounded in the numbers, with a proposed alternative.","task":"Write the 3-sentence message that voices the disagreement clearly and constructively.","tips":["State the disagreement plainly — hinting at it wastes the warning.","Ground it in the specific financial risk, not a general unease.","Pair the concern with an alternative so it's constructive, not just opposition."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-14","level":"senior","profession":"finance","title":"The restatement message to investors","scenario":"You have to tell investors you're restating prior results. This is among the hardest messages a CFO delivers. Clear is kind and clear is required: what's being restated, why, the size, and what's been done so it doesn't recur — no minimizing.","task":"Write the 3-4 sentence restatement communication that's direct and complete.","tips":["State plainly that you're restating and what periods — no soft-pedaling.","Give the cause and the magnitude honestly.","Close with the specific control fix; investors need to see it can't recur."],"focus":["clarity","precision"]},
    {"id":"hard-fin-senior-15","level":"senior","profession":"finance","title":"Denying the headcount request","scenario":"A director you respect asked you to add roles to their department and the budget genuinely can't support it. A vague 'let me see what I can do' is a slow no that erodes trust. Deliver the clean no now, with the reason and any flexibility.","task":"Write the 2-3 sentence no to the headcount request, direct and respectful.","tips":["A slow no is unkind — give the clear answer now.","State the constraint honestly: the budget, the priority ranking.","Offer real flexibility if any exists; don't fabricate hope."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-16","level":"senior","profession":"finance","title":"The feedback to a strong performer who overstepped","scenario":"Your best FP&A analyst went around you to give the CEO a forecast that hadn't been vetted, and it was wrong. You have to address it without crushing a strong performer. Behavior, impact, ask — specific and forward-looking, not a character verdict.","task":"Write the 3-sentence feedback: the specific behavior, its impact, and the ask.","tips":["Name the specific action, not a judgment about their ambition.","State the impact: an unvetted wrong number reached the CEO with your name on it.","Ask for the specific change and affirm the value of their initiative done right."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-17","level":"senior","profession":"finance","title":"Telling the board about the fraud finding","scenario":"An internal investigation found expense fraud by a mid-level manager. You have to brief the board. This news invites either downplaying or alarm; clear is kind means the facts, the exposure, the response, delivered steadily.","task":"Write the 3-sentence briefing: what was found, the exposure, and the response underway.","tips":["State the finding factually — no drama, no minimizing.","Quantify the exposure honestly, even if it's still an estimate.","Lead the response with what's already done: contained, referred, controls reviewed."],"focus":["clarity","precision"]},
    {"id":"hard-fin-senior-18","level":"senior","profession":"finance","title":"The 'we can't afford your project' to a VP","scenario":"A VP has a genuinely good project but there's no room in the budget this year. Telling them it's 'on the roadmap' when it isn't is a kindness that curdles into resentment. The honest message: not this year, here's why, here's when it could get real.","task":"Write the 2-3 sentences that decline the project honestly while respecting its merit.","tips":["Acknowledge the project is good — then give the real 'not now.'","Be honest about why: it's a prioritization call, not a quality one.","If there's a real future path, name the condition; if not, say so."],"focus":["clarity","audience"]},
    {"id":"hard-fin-senior-19","level":"senior","profession":"finance","title":"The pay-freeze message to the whole company","scenario":"Merit increases are frozen this year and you're delivering the news company-wide. People will be upset. Dressing it up ('pausing our compensation cycle to invest in stability') fools no one. Clear is kind: the freeze, the honest reason, and what it protects.","task":"Write the 3-sentence company message that delivers the freeze honestly and humanely.","tips":["Name it: merit increases are frozen this year. No euphemism.","Give the real reason and what the freeze protects — jobs, runway.","Acknowledge the impact on people honestly; don't pretend it's painless."],"focus":["clarity","audience"]},
    {"id":"hard-fin-senior-20","level":"senior","profession":"finance","title":"Telling the bank you'll breach","scenario":"You'll breach a covenant next quarter and you need to tell the lender before it happens, from a position of proactive honesty. Waiting or hedging makes it worse. Clear is kind: the likely breach, the timing, and your proposed path — delivered ahead of the event.","task":"Write the 2-3 sentence proactive message to the lender about the coming breach.","tips":["Lead with the honest heads-up — proactive beats caught.","State the likely breach, the quarter, and by how much.","Come with a proposed path — an amendment ask — not just a problem."],"focus":["clarity","impact"],"placeholder":"I want to flag this early, ahead of the numbers: we're likely to breach the leverage covenant in Q3, by roughly 0.2x, and I'd like to discuss an amendment now rather than at the wire."},
    {"id":"hard-fin-senior-21","level":"senior","profession":"finance","title":"The no to a peer's cross-charge","scenario":"Another exec wants to cross-charge their overrun to your budget, and it's not legitimate. A conflict-avoidant 'let me think about it' invites pressure. The clean answer: no, with the principle, delivered without making it personal.","task":"Write the 2-3 sentence no to the cross-charge, principled and non-personal.","tips":["Say no clearly and name the principle, not the person.","Keep it about the accounting logic, not the relationship.","Offer the legitimate path if there is one; hold the line if there isn't."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-22","level":"senior","profession":"finance","title":"Delivering the write-down to the acquisition team","scenario":"The acquisition you all championed is being written down, and you have to tell the deal team who worked on it for a year. It's a hard, personal message. Clear is kind: name the write-down, own the collective call, and separate the outcome from a verdict on their work.","task":"Write the 3-sentence message that delivers the write-down to the team honestly and fairly.","tips":["State the write-down plainly — the team will hear it publicly regardless.","Own it as a collective decision, not a search for whose fault it was.","Separate a bad outcome from bad work where that's honest to do."],"focus":["clarity","audience"]},
    {"id":"hard-fin-senior-23","level":"senior","profession":"finance","title":"The hard truth in the CEO's ear before the board","scenario":"Before the board meeting, you need to tell the CEO privately that the number they're about to present is softer than they think. Letting them walk in unprepared would be the disloyal move. Clear is kind: the real number, the gap, and the recommended reframe — now, in private.","task":"Write the 2-3 sentence private heads-up that gives the CEO the hard truth and a path.","tips":["Deliver the hard truth privately, before the room, where it helps.","State the real number and the gap from what they expect.","Give them the reframe so they walk in prepared, not blindsided."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-24","level":"senior","profession":"finance","title":"The no to extending payment terms","scenario":"A major customer's procurement team is pushing hard for 120-day terms and your sales lead wants to say yes to save the deal. You have to deliver the no, or the boundary, in a way that holds. Clear is kind: the limit, the reason, and the flexibility that exists.","task":"Write the 2-3 sentences that hold the payment-terms line while keeping the deal alive.","tips":["State the boundary clearly: terms cap at 60 days, and why.","Give the real reason — cash cost — without lecturing.","Offer the flexibility that exists: a discount for faster pay, perhaps."],"focus":["clarity","impact"]},
    {"id":"hard-fin-senior-25","level":"senior","profession":"finance","title":"Telling the whole company the year missed","scenario":"The year came in below plan and you're addressing the company at the year-end all-hands. Spinning a miss as a win ('resilient performance in a tough environment') insults an audience that knows the truth. Clear is kind: name the miss, own it collectively, and be honest about next year.","task":"Write the 3-4 sentence year-end message that delivers the miss with honesty and steadiness.","tips":["Name the miss plainly — the company knows, and pretending erodes trust.","Own it collectively without assigning blame to any team.","Be honest and specific about next year, not vaguely upbeat."],"focus":["clarity","audience"]}
  ],
  "putting-it-together": [
    {"id":"together-fin-senior-01","level":"senior","profession":"finance","title":"The full board memo under a page limit","scenario":"You have one page to recommend the capital raise to the board — BLUF, structure, evidence, owned recommendation, and a pre-empted objection, all under real space constraint. Everything the course taught has to work at once, edited to fit.","task":"Write the one-page memo's core: recommendation first, three supporting points, one pre-empted objection, in under 150 words.","tips":["Lead with the recommendation; the page limit forbids warm-up.","Three supports, one objection answered — no room for a fourth of anything.","Edit like a reader: cut every word a director wouldn't miss."],"focus":["structure","impact"],"placeholder":"I recommend we raise $50M in equity now to fund the integration and hold leverage flat."},
    {"id":"together-fin-senior-02","level":"senior","profession":"finance","title":"The same news, three channels","scenario":"The guidance cut has to go to the board (formal memo), the exec team (Slack heads-up), and your direct reports (a quick verbal). Same core message, three registers. Matching register to channel is the integration skill here.","task":"Write the one-line Slack version and the opening line of the board memo — same news, right register for each.","tips":["The Slack line is direct and brief; the board memo is measured and complete.","Same fact, but the tone and detail match the channel.","Don't send the board a Slack line or the team a board memo."],"focus":["audience","concision"]},
    {"id":"together-fin-senior-03","level":"senior","profession":"finance","title":"The earnings-call answer that does everything","scenario":"An analyst asks whether margins are sustainable. A great answer leads with the point, is structured, precise, owns a view, and stays tight — all in twenty seconds live. This is every skill compressed into one spoken moment.","task":"Write the 3-4 sentence spoken answer that integrates BLUF, structure, precision, and presence.","tips":["Point first: yes, sustainable — then the structure.","One precise number as evidence, not a data dump.","Own it with a confident close; keep the whole thing under thirty seconds."],"focus":["structure","impact"],"placeholder":"Yes, they're sustainable — the gains are structural, not timing. Two-thirds come from the pricing change, which is permanent, and one-third from mix, which holds. We expect to sustain margins in this range through the year."},
    {"id":"together-fin-senior-04","level":"senior","profession":"finance","title":"Editing the CFO letter like a reader","scenario":"Your results letter draft is complete but bloated — good content, poor economy. The final skill is editing: reading it as a busy investor would and cutting everything that doesn't earn its place, tightening for register and flow.","task":"Take a 60-word bloated paragraph you'd expect in such a letter and rewrite it to 30 tight words.","tips":["Read as the investor: where do they skim, and why?","Cut hedges, redundant pairs, and meta-commentary first.","Preserve the register — tightening isn't the same as casual."],"focus":["concision","clarity"]},
    {"id":"together-fin-senior-05","level":"senior","profession":"finance","title":"The whole-company message under scrutiny","scenario":"You're announcing the cost program to the entire company. It must lead with the point, start from the employees' stake, be honest about hard parts, persuade toward the program, and read cleanly. Everything at once, for the hardest audience.","task":"Write the 4-sentence company message that integrates BLUF, audience, honesty, and persuasion.","tips":["Lead with what's happening, from their stake, not the board's.","Be honest about the hard parts — the room detects spin.","Persuade toward the why while reading clean and unhedged."],"focus":["audience","impact"]},
    {"id":"together-fin-senior-06","level":"senior","profession":"finance","title":"The banker email that closes the ask","scenario":"You're emailing the lead banker to request the amendment: BLUF the ask, structure the case, give precise terms, own the recommendation, and keep it short enough that a busy banker reads it all. Real constraint, every skill.","task":"Write the complete 5-6 sentence email integrating the ask, the case, and the terms.","tips":["Ask first, terms early, rationale tight.","A banker reads for the deal shape — give it fast and precisely.","Own the ask; a hedged request invites a hedged reply."],"focus":["structure","concision"]},
    {"id":"together-fin-senior-07","level":"senior","profession":"finance","title":"The 90-second board verbal update","scenario":"The chair asks you for a 90-second verbal on the quarter, no slides. You have to lead with the headline, give it structure, land the key numbers precisely, and close with a view — all spoken, all tight, no notes to hide behind.","task":"Write the 90-second spoken update integrating headline, structure, precision, and a closing view.","tips":["Headline in the first sentence; the chair is timing you.","Three parts, signposted, so it's followable without slides.","Precise numbers, a clear view to close — then stop on time."],"focus":["structure","impact"]},
    {"id":"together-fin-senior-08","level":"senior","profession":"finance","title":"The hard message that persuades too","scenario":"You're telling the board you need to cut guidance AND asking them to approve a strategy shift in response. The message must deliver bad news clearly and persuade toward the pivot — hard-message discipline and persuasion in one memo.","task":"Write the 4-sentence memo that delivers the cut and persuades toward the response.","tips":["Front-load the hard news; don't bury it under the pivot pitch.","Then move to the response with a before/after that earns the pivot.","Balance honesty about the miss with credible confidence in the plan."],"focus":["impact","structure"]},
    {"id":"together-fin-senior-09","level":"senior","profession":"finance","title":"Adapting the deck for two rooms in one day","scenario":"You present the same financials to the board in the morning and the lenders in the afternoon. The board wants strategy and growth; the lenders want cash and downside. Same data, two entirely different framings — audience calibration under time pressure.","task":"Write the opening line for each version — board and lender — from the same quarter's data.","tips":["Board opener: growth and strategic progress.","Lender opener: cash generation and covenant headroom.","Same numbers underneath; the lead reflects who's listening."],"focus":["audience","structure"]},
    {"id":"together-fin-senior-10","level":"senior","profession":"finance","title":"The all-hands Q&A curveball","scenario":"At the all-hands, an employee asks a hard question about executive pay during cuts. You must answer the actual question, honestly, with structure and presence, under live pressure and a skeptical room — pressure-handling and audience skills at once.","task":"Write the 3-4 sentence live answer that integrates answering-the-question, honesty, and presence.","tips":["Answer the real fairness question first, not a deflection.","Be honest about the mechanics; the room punishes spin.","Hold your presence — steady, direct, not defensive."],"focus":["audience","impact"]},
    {"id":"together-fin-senior-11","level":"senior","profession":"finance","title":"The investor email that survives forwarding","scenario":"An institutional investor emailed a pointed question and your reply will be forwarded to their whole team. It must answer directly, be precise, own a view, and read cleanly out of context — because it will be read out of context.","task":"Write the 3-4 sentence reply built to be forwarded: direct, precise, self-contained.","tips":["Answer the question in the first line — it'll be quoted.","Make each sentence stand on its own; context won't travel.","Precise and owned; a forwarded hedge looks worse to strangers."],"focus":["precision","clarity"]},
    {"id":"together-fin-senior-12","level":"senior","profession":"finance","title":"The one-slide capital-allocation story","scenario":"You have exactly one slide to make the capital-allocation recommendation to the board. Governing idea, three supports, the recommendation owned, the numbers precise — all on one slide that reads in thirty seconds. Extreme integration under space constraint.","task":"Write the slide's headline and three bullet lines — the whole argument, tight.","tips":["Headline states the recommendation, not a topic.","Three bullets, each a support with its number — no prose paragraphs.","If a director reads only the headline, they get the answer."],"focus":["structure","concision"],"placeholder":"Headline: Direct this year's $40M excess cash to debt paydown."},
    {"id":"together-fin-senior-13","level":"senior","profession":"finance","title":"The reforecast memo, fully realized","scenario":"You're writing the reforecast memo: it must BLUF the revised numbers, structure the drivers, be precise, own your read, pre-empt the board's objection, and stay under two pages. This is the flagship CFO artifact with every skill in play.","task":"Write the memo's opening paragraph (4-5 sentences) integrating BLUF, precision, and an owned view.","tips":["Revised number first, with the change quantified.","Drivers structured by size; your read stated as judgment.","Pre-empt the 'is this the floor?' question in the opening."],"focus":["structure","precision"]},
    {"id":"together-fin-senior-14","level":"senior","profession":"finance","title":"The rapid Slack decision thread","scenario":"The exec team is deciding in Slack whether to draw the revolver today. You need to state your recommendation, the reason, and the risk in a message people read on their phones between meetings — presence and concision in an informal channel.","task":"Write the 2-3 sentence Slack message that gives a clear recommendation fast.","tips":["Recommendation first, even on Slack — maybe especially on Slack.","One reason, one risk; phone-readable.","Match the channel's speed without losing the substance."],"focus":["concision","impact"],"placeholder":"My rec: draw $10M on the revolver today for the buffer. The Meridian payment is uncertain and I'd rather have the cushion than scramble Friday. Downside is a week of interest — cheap insurance."},
    {"id":"together-fin-senior-15","level":"senior","profession":"finance","title":"The board pre-read and the verbal, aligned","scenario":"You send a board pre-read, then present verbally. The two must reinforce, not repeat — the pre-read carries the analysis, the verbal carries the message and the ask. Integrating written and spoken so each does its own job.","task":"Write the pre-read's one-line thesis and the different verbal opening that builds on it.","tips":["The pre-read thesis orients; the verbal opening advances.","Don't read the pre-read aloud — the verbal adds the human case.","Together they should feel like one argument in two modes."],"focus":["structure","audience"]},
    {"id":"together-fin-senior-16","level":"senior","profession":"finance","title":"The cost-program update that holds every month","scenario":"Your monthly steering-committee update needs a repeatable structure (progress, risks, asks), precise metrics, an owned status, and tight prose — a template that carries the whole skill set and reads fast every single month.","task":"Write this month's update in the fixed frame: progress, risks, asks — precise and tight.","tips":["Same three sections every month builds reading speed.","Quantify against the same baseline; own the status honestly.","The 'asks' section is where the update earns its meeting slot."],"focus":["structure","precision"]},
    {"id":"together-fin-senior-17","level":"senior","profession":"finance","title":"The acquisition recommendation, end to end","scenario":"You're presenting the acquisition to the investment committee: recommendation up front, a narrative case, precise numbers, the strongest objection pre-empted, and an owned verdict — the complete persuasive artifact under committee time pressure.","task":"Write the opening 4-5 sentences integrating recommendation, narrative, and a pre-empted objection.","tips":["Verdict and price first; the committee decides early.","Wrap the numbers in a narrative — the gap this fills.","Name and answer the strongest objection before someone raises it."],"focus":["structure","impact"]},
    {"id":"together-fin-senior-18","level":"senior","profession":"finance","title":"The crisis message at 9pm","scenario":"A payment system failed and payroll may be late. At 9pm you must message the CEO and the exec team: what happened, the impact, what you're doing, and what you need — clear, structured, and calm under real pressure, on a phone.","task":"Write the 3-4 sentence crisis message integrating clarity, structure, and a clear ask under pressure.","tips":["Lead with the situation and the impact — no wind-up at 9pm.","Structure it: what happened, what it affects, what you're doing.","End with the specific ask or the reassurance; stay calm in the prose."],"focus":["clarity","structure"],"placeholder":"Heads-up: our payment processor is down and payroll scheduled for tomorrow is at risk. Impact is roughly 400 employees; we're on with the vendor now and have a manual backup ready if needed. I'll update by 11pm — no action needed from you yet."},
    {"id":"together-fin-senior-19","level":"senior","profession":"finance","title":"The IR FAQ that serves everyone","scenario":"You're writing the IR FAQ answer on why opex grew faster than revenue. It must be precise enough for analysts and plain enough for retail holders, structured, and tight — audience calibration and precision balanced in one paragraph.","task":"Write the 3-4 sentence FAQ answer that satisfies the analyst and the retail holder at once.","tips":["Plain framing first, then one precise anchor for the analysts.","Structure it so both audiences find their level.","Delete any term you'd have to define but can't in the space."],"focus":["audience","precision"]},
    {"id":"together-fin-senior-20","level":"senior","profession":"finance","title":"The negotiation close with the bank","scenario":"You're in the final financing negotiation and it's your turn to close: restate the deal you want, hold the line on the two terms that matter, concede the one that doesn't, and land it — presence, precision, and persuasion in a live high-stakes moment.","task":"Write the 3-4 sentence closing statement that lands the deal you want.","tips":["Restate the deal clearly so there's no ambiguity to exploit.","Hold firm on the two terms that matter; signal the concession on the third.","Close with confidence — a hesitant close reopens what you settled."],"focus":["impact","precision"]},
    {"id":"together-fin-senior-21","level":"senior","profession":"finance","title":"The year-end company address","scenario":"Your year-end all-hands address covers a mixed year: some wins, a miss, a hard outlook. It must be honest, lead with a clear message, be structured, persuade toward next year, and read as steady leadership — the full toolkit in a high-stakes speech.","task":"Write the 4-5 sentence core of the address integrating honesty, structure, and steady presence.","tips":["Open with the honest headline of the year — good and bad.","Structure it so the miss and the wins each get their due.","Close on a specific, credible forward view, not vague optimism."],"focus":["audience","impact"]},
    {"id":"together-fin-senior-22","level":"senior","profession":"finance","title":"The two-minute audit-committee brief","scenario":"You have two minutes to brief the audit committee on a control issue: what happened, the exposure, the remediation, and your assessment — precise, structured, honest, and owned, with no room to ramble. Every skill compressed into a tight brief.","task":"Write the 4-sentence brief integrating the facts, the exposure, and your owned assessment.","tips":["Lead with what happened and whether there was any loss.","Structure: issue, exposure, remediation, assessment.","Own the assessment — the committee wants your judgment, not just facts."],"focus":["structure","precision"]},
    {"id":"together-fin-senior-23","level":"senior","profession":"finance","title":"The investor-day segment that lands","scenario":"You have your ten-minute finance segment at the investor day. It must open with the story, structure the financial case, hit precise numbers, own the guidance, and stay tight enough to end on time — the flagship spoken performance.","task":"Write the segment's opening 4-5 sentences integrating narrative, structure, and owned guidance.","tips":["Open with the financial story, not a metrics list.","Structure the ten minutes and signpost so analysts can follow.","Own the guidance number cleanly — it's the line they'll quote."],"focus":["structure","impact"]},
    {"id":"together-fin-senior-24","level":"senior","profession":"finance","title":"The email that has to do three jobs","scenario":"You're emailing the CEO to report a miss, recommend a response, and request a decision by Friday — three jobs in one message that must stay short and clear. Integration means doing all three without the email sprawling or burying any of them.","task":"Write the complete 4-5 sentence email that reports, recommends, and requests a decision.","tips":["Three jobs, three clean moves — report, recommend, request.","Each gets its own sentence or two; none buries the others.","End with the decision needed and the Friday deadline, unmissable."],"focus":["structure","clarity"],"placeholder":"Two things and a decision needed by Friday. First, we'll miss Q2 by about 3% — I'll send the drivers separately."},
    {"id":"together-fin-senior-25","level":"senior","profession":"finance","title":"The capstone: the full board deck narrative","scenario":"You're building the entire Q4 board deck narrative — the executive summary that governs the whole thing. It must have one governing idea, lead with the point, calibrate to directors, own the recommendations, be precise, and read tight. This is everything, integrated, in the CFO's most important recurring artifact.","task":"Write the executive summary (5-6 sentences) that integrates every skill: governing idea, BLUF, precision, and owned recommendations.","tips":["One governing idea at the top that the whole quarter supports.","Lead with the point; directors read the summary and skim the rest.","Precise numbers, owned recommendations, director-altitude throughout — and cut every spare word."],"focus":["structure","impact"],"placeholder":"The quarter's story: we beat plan while investing ahead of growth, and we're asking the board to approve two moves that extend that position."}
  ],
};
